              ${caja.saldo.toLocaleString("es-AR", { minimumFractionDigits: 2 })}
            </p>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto px-6 py-10 w-full space-y-8">
        {/* Actions */}
        <div className="flex items-center justify-between gap-4">
           <div className="flex gap-3">
