            </button>
          ))}

          <button className="border-2 border-dashed border-gray-300 rounded-2xl p-6 flex flex-col items-center justify-center gap-3 text-gray-400 hover:text-red-600 hover:border-red-600/50 hover:bg-red-50/10 transition-all group">
            <div className="p-4 bg-gray-100 rounded-full group-hover:bg-red-100">
              <Plus size={32} />
            </div>
            <span className="text-xs font-black uppercase tracking-[0.2em]">Agregar Entidad</span>
          </button>
        </div>
      </main>
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import Link from "next/link";
import { 
  ArrowLeft, ArrowRightLeft, History, 
  Calendar, ArrowRight, ArrowUpRight, ArrowDownLeft 
} from "lucide-react";
import { Drawer } from "@/components/ui/Drawer";

interface Transferencia {
  id: string;
  fecha: string;
  monto: number;
  descripcion?: string | null;
  formaPagoOrigen: string;
  formaPagoDestino: string;
  cajaOrigen: { nombre: string };
  cajaDestino: { nombre: string };
}

interface Caja { id: string; nombre: string; }

const FORMAS_PAGO = ["EFECTIVO", "TRANSFERENCIA", "CHEQUE", "TARJETA", "MERCADO PAGO", "OTRO"];

export default function TransferenciasPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [transferencias, setTransferencias] = useState<Transferencia[]>([]);
  const [loading, setLoading] = useState(true);
  const [mostrarForm, setMostrarForm] = useState(false);
  const [cajas, setCajas] = useState<Caja[]>([]);
  const [cajaOrigenId, setCajaOrigenId] = useState("");
  const [cajaDestinoId, setCajaDestinoId] = useState("");
  const [monto, setMonto] = useState("");
  const [descripcion, setDescripcion] = useState("");
  const [formaPagoOrigen, setFormaPagoOrigen] = useState("EFECTIVO");
  const [formaPagoDestino, setFormaPagoDestino] = useState("EFECTIVO");
  const [guardando, setGuardando] = useState(false);

  useEffect(() => {
    if (status === "unauthenticated") router.push("/login");
  }, [status, router]);

  const cargar = () => {
    fetch("/api/cajas/transferencias")
      .then((r) => r.json())
      .then((d) => { setTransferencias(d); setLoading(false); })
      .catch(() => setLoading(false));
  };

  useEffect(() => { cargar(); }, []);

  useEffect(() => {
    fetch("/api/cajas").then((r) => r.json()).then((d) => {
      setCajas(d);
      if (d.length >= 2) { setCajaOrigenId(d[0].id); setCajaDestinoId(d[1].id); }
    });
  }, []);

  const guardar = async () => {
    if (!cajaOrigenId || !cajaDestinoId || !monto || cajaOrigenId === cajaDestinoId) return;
    setGuardando(true);

    await fetch("/api/cajas/transferencias", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ 
        cajaOrigenId, 
        cajaDestinoId, 
        monto, 
        descripcion: (descripcion || "Transferencia operativa").toUpperCase(), 
        formaPagoOrigen, 
        formaPagoDestino 
      }),
    });

    setMostrarForm(false);
    setMonto(""); setDescripcion("");
    setGuardando(false);
    cargar();
  };

  if (status === "loading" || loading) return (
    <div className="flex flex-col items-center justify-center p-40">
      <div className="w-12 h-1 bg-red-600 rounded-full animate-pulse mb-4" />
      <div className="text-gray-400 font-medium text-sm animate-pulse">Cargando transferencias...</div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <Link href="/cajas" className="p-2 text-gray-400 hover:text-red-600 hover:bg-gray-50 rounded-xl transition-all">
              <ArrowLeft size={24} />
            </Link>
            <div>
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Tesorería</p>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Transferencias entre Cajas</h1>
            </div>
          </div>
          <button
            onClick={() => setMostrarForm(true)}
            className="bg-red-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-600/10 flex items-center gap-2"
          >
            <ArrowRightLeft size={18} /> Nueva Transferencia
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto px-6 py-10 w-full space-y-8">
        <div className="space-y-4">
          {transferencias.map((t, idx) => (
            <div 
              key={t.id} 
              className="group bg-white p-6 rounded-2xl border border-gray-200 hover:shadow-md transition-all"
            >
              <div className="flex flex-col md:flex-row md:items-center gap-6">
                <div className="flex items-center gap-4">
                   <div className="px-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-center min-w-[120px]">
                      <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Origen</p>
                      <p className="text-sm font-bold text-gray-900 uppercase">{t.cajaOrigen.nombre}</p>
                   </div>
                   <ArrowRight size={20} className="text-gray-300" />
                   <div className="px-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-center min-w-[120px]">
                      <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Destino</p>
                      <p className="text-sm font-bold text-gray-900 uppercase">{t.cajaDestino.nombre}</p>
                   </div>
                </div>

                <div className="flex-1 min-w-0">
                  <div className="flex items-center justify-between gap-4">
                    <div>
                      <p className="text-base font-bold text-gray-900 group-hover:text-red-600 transition-colors uppercase">
                        {t.descripcion || "Transferencia Operativa"}
                      </p>
                      <div className="flex items-center gap-3 mt-1">
                         <div className="flex items-center gap-1.5 text-gray-400 text-[10px] font-medium uppercase">
                            <Calendar size={12} />
                            {new Date(t.fecha).toLocaleDateString("es-AR")}
                         </div>
                         <span className="text-[10px] text-gray-300 font-bold uppercase">{t.formaPagoOrigen} <ArrowRight size={10} className="inline mx-0.5" /> {t.formaPagoDestino}</span>
                      </div>
                    </div>

                    <div className="text-right">
                       <p className="text-xl font-bold tabular-nums text-gray-900">
                          ${t.monto.toLocaleString("es-AR", { minimumFractionDigits: 2 })}
                       </p>
                       <span className="text-[9px] font-bold text-emerald-600 uppercase tracking-wider bg-emerald-50 px-2 py-0.5 rounded border border-emerald-100">Confirmado</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ))}
          {transferencias.length === 0 && (
            <div className="py-20 text-center bg-white rounded-3xl border-2 border-dashed border-gray-100">
               <ArrowRightLeft size={48} className="text-gray-200 mx-auto mb-4" />
               <p className="text-gray-400 font-medium">No hay transferencias registradas</p>
            </div>
          )}
        </div>
      </main>

      <Drawer 
        isOpen={mostrarForm} 
        onClose={() => setMostrarForm(false)} 
        title="Nueva Transferencia"
      >
        <div className="p-1 space-y-8">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Caja Origen</label>
              <select 
                value={cajaOrigenId} onChange={e => setCajaOrigenId(e.target.value)}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none appearance-none cursor-pointer"
              >
                {cajas.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Caja Destino</label>
              <select 
                value={cajaDestinoId} onChange={e => setCajaDestinoId(e.target.value)}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none appearance-none cursor-pointer"
              >
                {cajas.filter((c) => c.id !== cajaOrigenId).map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-2">
             <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Monto a Transferir</label>
             <div className="relative">
                <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 font-bold">$</span>
                <input 
                  type="number" min="0" step="0.01" value={monto} onChange={(e) => setMonto(e.target.value)}
                  placeholder="0.00"
                  className="w-full pl-10 pr-5 py-4 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-lg font-bold outline-none transition-all placeholder:text-gray-200" 
                />
             </div>
          </div>

          <div className="space-y-2">
             <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Descripción (Opcional)</label>
             <input 
               type="text" value={descripcion} onChange={e => setDescripcion(e.target.value)}
               placeholder="Motivo de la transferencia..."
               className="w-full px-5 py-4 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-medium outline-none" 
             />
          </div>

          <div className="p-5 bg-gray-50 rounded-2xl border border-gray-200 space-y-4">
             <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest text-center">Métodos de Pago</p>
             <div className="grid grid-cols-2 gap-4">
                <select value={formaPagoOrigen} onChange={e => setFormaPagoOrigen(e.target.value)}
                  className="w-full px-3 py-2.5 bg-white border border-gray-200 rounded-lg text-xs font-bold outline-none uppercase appearance-none cursor-pointer">
                  {FORMAS_PAGO.map((f) => <option key={f} value={f}>{f}</option>)}
                </select>
                <select value={formaPagoDestino} onChange={e => setFormaPagoDestino(e.target.value)}
                  className="w-full px-3 py-2.5 bg-white border border-gray-200 rounded-lg text-xs font-bold outline-none uppercase appearance-none cursor-pointer">
                  {FORMAS_PAGO.map((f) => <option key={f} value={f}>{f}</option>)}
                </select>
             </div>
          </div>

          <div className="pt-6">
            <button
              onClick={guardar} disabled={guardando || !monto || cajaOrigenId === cajaDestinoId}
              className="w-full py-4 bg-red-600 text-white rounded-xl text-sm font-bold hover:bg-red-700 transition-all active:scale-[0.98] shadow-lg shadow-red-600/20"
            >
              {guardando ? "Procesando..." : "Confirmar Transferencia"}
            </button>
          </div>
        </div>
      </Drawer>
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import Link from "next/link";
import { 
  ArrowLeft, Search, Plus, CreditCard, Landmark, 
  History, AlertCircle, Calendar,
  User, Building2, Timer
} from "lucide-react";
import { Drawer } from "@/components/ui/Drawer";
import { StatusBadge } from "@/components/ui/StatusBadge";

interface Cheque {
  id: string;
  estado: string;
  numeroCheque?: string | null;
  banco?: string | null;
  librador?: string | null;
  importe: number;
  fechaIngreso: string;
  fechaEmision?: string | null;
  fechaCobro?: string | null;
  endosadoA?: string | null;
  descripcion?: string | null;
  diasVencimiento?: number | null;
  vencimientoTexto?: string;
  cliente?: { nombre: string; empresa?: { nombre: string } | null } | null;
}

interface Cliente { id: string; nombre: string; empresa?: { nombre: string } | null; }

export default function ChequesPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [cheques, setCheques] = useState<Cheque[]>([]);
  const [loading, setLoading] = useState(true);
  const [mostrarForm, setMostrarForm] = useState(false);
  const [clientes, setClientes] = useState<Cliente[]>([]);
  const [busqueda, setBusqueda] = useState("");

  const [clienteId, setClienteId] = useState("");
  const [numeroCheque, setNumeroCheque] = useState("");
  const [banco, setBanco] = useState("");
  const [librador, setLibrador] = useState("");
  const [importe, setImporte] = useState("");
  const [fechaEmision, setFechaEmision] = useState("");
  const [fechaCobro, setFechaCobro] = useState("");
  const [endosadoA, setEndosadoA] = useState("");
  const [descripcion, setDescripcion] = useState("");
  const [estadoForm, setEstadoForm] = useState("EN_CARTERA");
  const [guardando, setGuardando] = useState(false);

  useEffect(() => {
    if (status === "unauthenticated") router.push("/login");
  }, [status, router]);

  const cargar = () => {
    fetch("/api/cheques").then((r) => r.json()).then((d) => { setCheques(d); setLoading(false); }).catch(() => setLoading(false));
  };

  useEffect(() => { cargar(); }, []);
  useEffect(() => {
    fetch("/api/clientes").then((r) => r.json()).then(setClientes);
  }, []);

  const filtrados = cheques.filter((c: Cheque) => {
    const texto = busqueda.toLowerCase();
    return (
      (c.numeroCheque || "").includes(texto) ||
      (c.librador || "").toLowerCase().includes(texto) ||
      (c.banco || "").toLowerCase().includes(texto) ||
      (c.cliente?.nombre || "").toLowerCase().includes(texto)
    );
  });

  const guardar = async () => {
    if (!importe) return;
    setGuardando(true);
    await fetch("/api/cheques", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ 
        clienteId: clienteId || null, 
        numeroCheque, 
        banco: banco.toUpperCase(), 
        librador: librador.toUpperCase(), 
        importe, 
        fechaEmision, 
        fechaCobro, 
        endosadoA, 
        descripcion: (descripcion || "").toUpperCase(), 
        estado: estadoForm 
      }),
    });
    setMostrarForm(false);
    setNumeroCheque(""); setBanco(""); setLibrador(""); setImporte(""); setFechaEmision(""); setFechaCobro(""); setEndosadoA(""); setDescripcion(""); setClienteId("");
    setGuardando(false);
    cargar();
  };

  if (status === "loading" || loading) return (
    <div className="flex flex-col items-center justify-center p-40">
      <div className="w-12 h-1 bg-amber-600 rounded-full animate-pulse mb-4" />
      <div className="text-gray-400 font-medium text-sm animate-pulse">Cargando cheques...</div>
    </div>
  );

  const totalCartera = cheques
    .filter((c: Cheque) => c.estado === "EN_CARTERA")
    .reduce((sum: number, c: Cheque) => sum + c.importe, 0);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <Link href="/cajas" className="p-2 text-gray-400 hover:text-red-600 hover:bg-gray-50 rounded-xl transition-all">
              <ArrowLeft size={24} />
            </Link>
            <div>
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Tesorería</p>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Cartera de Cheques</h1>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden md:block bg-amber-50 px-4 py-2 rounded-xl border border-amber-100">
                <p className="text-[9px] font-bold text-amber-600 uppercase tracking-wider mb-0.5">Total en Cartera</p>
                <p className="text-lg font-bold tabular-nums text-amber-700">
                  ${totalCartera.toLocaleString("es-AR", { minimumFractionDigits: 2 })}
                </p>
             </div>
             <button
              onClick={() => setMostrarForm(true)}
              className="bg-red-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-600/10 flex items-center gap-2"
            >
              <Plus size={18} /> Recibir Cheque
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-6xl mx-auto px-6 py-10 w-full space-y-8">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-gray-200 shadow-sm">
           <div className="relative w-full max-w-lg">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
              <input 
                type="text" 
                placeholder="Buscar por n°, librador, banco o cliente..." 
                value={busqueda}
                onChange={(e) => setBusqueda(e.target.value)}
                className="w-full pl-12 pr-4 py-2.5 bg-gray-50 border border-transparent focus:border-red-600 rounded-xl text-sm font-medium outline-none transition-all"
              />
           </div>
           <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider bg-gray-50 px-3 py-2 rounded-lg border border-gray-100 italic">
              {filtrados.length} valores encontrados
           </div>
        </div>

        <div className="space-y-4">
          {filtrados.map((c: Cheque) => (
            <div 
              key={c.id} 
              className="group bg-white p-6 rounded-2xl border border-gray-200 hover:shadow-md transition-all relative overflow-hidden"
            >
              <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-center">
                <div className="md:col-span-4">
                   <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mb-1">Origen / Cliente</p>
                   <p className="text-base font-bold text-gray-900 leading-tight uppercase">
                    {c.cliente?.empresa?.nombre
                      ? `${c.cliente.empresa.nombre} - ${c.cliente.nombre}`
                      : c.cliente?.nombre || "Emisor Particular"}
                   </p>
                   <div className="flex items-center gap-1.5 mt-2 text-amber-700 bg-amber-50 px-2 py-0.5 rounded border border-amber-100 w-fit text-[10px] font-bold uppercase">
                      <Landmark size={12} /> {c.banco || "S/D"}
                   </div>
                </div>

                <div className="md:col-span-3">
                   <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mb-1">Librador / N°</p>
                   <p className="text-sm font-bold text-gray-600 uppercase">{c.librador || "N/A"}</p>
                   <p className="text-[10px] font-medium text-gray-400 mt-1 uppercase">N°: {c.numeroCheque || "----"}</p>
                </div>

                <div className="md:col-span-2">
                   <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mb-1">Fecha Cobro</p>
                   <p className="text-sm font-bold text-gray-900">
                      {c.fechaCobro ? new Date(c.fechaCobro).toLocaleDateString("es-AR") : "Inmediata"}
                   </p>
                   <div className="flex items-center gap-1.5 mt-1">
                       <Timer size={12} className={c.diasVencimiento != null && c.diasVencimiento < 0 ? "text-red-500" : "text-gray-300"} />
                       <span className={`text-[10px] font-bold uppercase ${c.diasVencimiento != null && c.diasVencimiento < 0 ? "text-red-600" : "text-gray-400"}`}>
                          {c.vencimientoTexto || "S/D"}
                       </span>
                   </div>
                </div>

                <div className="md:col-span-3 text-right">
                   <p className="text-xl font-bold tabular-nums text-gray-900 mb-2">
                      ${c.importe.toLocaleString("es-AR", { minimumFractionDigits: 2 })}
                   </p>
                   <StatusBadge status={c.estado} />
                </div>
              </div>
            </div>
          ))}
          {filtrados.length === 0 && (
            <div className="py-20 text-center bg-white rounded-3xl border-2 border-dashed border-gray-100">
               <Landmark size={48} className="text-gray-100 mx-auto mb-4" />
               <p className="text-gray-400 font-medium">No se encontraron cheques</p>
            </div>
          )}
        </div>
      </main>

      <Drawer 
        isOpen={mostrarForm} 
        onClose={() => setMostrarForm(false)} 
        title="Recibir Cheque"
      >
        <div className="p-1 space-y-6">
          <div className="space-y-2">
            <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Cliente / Origen</label>
            <select 
              value={clienteId} onChange={e => setClienteId(e.target.value)}
              className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none uppercase appearance-none cursor-pointer"
            >
              <option value="">SIN CLIENTE ASIGNADO</option>
              {clientes.map((c) => <option key={c.id} value={c.id}>{c.empresa ? `${c.empresa.nombre} - ${c.nombre}`.toUpperCase() : c.nombre.toUpperCase()}</option>)}
            </select>
          </div>

          <div className="space-y-2">
             <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Importe del Cheque</label>
             <div className="relative">
                <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 font-bold">$</span>
                <input 
                  type="number" min="0" step="0.01" value={importe} onChange={(e) => setImporte(e.target.value)}
                  placeholder="0.00"
                  className="w-full pl-10 pr-5 py-4 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-xl font-bold outline-none transition-all placeholder:text-gray-200" 
                />
             </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div className="space-y-2">
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">N° Cheque</label>
                <input type="text" value={numeroCheque} onChange={e => setNumeroCheque(e.target.value)}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none" />
             </div>
             <div className="space-y-2">
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Banco</label>
                <input type="text" value={banco} onChange={e => setBanco(e.target.value)}
                  placeholder="Banco emisor..."
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none uppercase placeholder:text-gray-300" />
             </div>
          </div>

          <div className="space-y-2">
             <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Librador (Firmante)</label>
             <input type="text" value={librador} onChange={e => setLibrador(e.target.value)}
               placeholder="Nombre de quien firma..."
               className="w-full px-5 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none uppercase placeholder:text-gray-300" />
          </div>

          <div className="grid grid-cols-2 gap-4 p-4 bg-gray-50 rounded-2xl border border-gray-100">
             <div className="space-y-2">
                <label className="text-[10px] font-bold uppercase tracking-widest text-gray-400">Fecha Emisión</label>
                <input type="date" value={fechaEmision} onChange={e => setFechaEmision(e.target.value)}
                  className="w-full bg-white border border-gray-200 p-2 rounded-lg text-sm outline-none" />
             </div>
             <div className="space-y-2">
                <label className="text-[10px] font-bold uppercase tracking-widest text-red-600">Fecha Cobro</label>
                <input type="date" value={fechaCobro} onChange={e => setFechaCobro(e.target.value)}
                  className="w-full bg-white border border-red-200 p-2 rounded-lg text-sm outline-none" />
             </div>
          </div>

          <div className="pt-6">
            <button
              onClick={guardar} disabled={guardando || !importe}
              className="w-full py-4 bg-red-600 text-white rounded-xl text-sm font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-600/20 active:scale-[0.98]"
            >
              {guardando ? "Procesando..." : "Confirmar Recepción"}
            </button>
          </div>
        </div>
      </Drawer>
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter, useParams } from "next/navigation";
import { useEffect, useState } from "react";
import Link from "next/link";
import { ArrowLeft, User, Phone, Mail, MapPin, CreditCard, FileText, Receipt, History, ExternalLink, Briefcase, Printer } from "lucide-react";

interface ClienteDetalle {
  id: string;
  nombre: string;
  telefono?: string | null;
  email?: string | null;
  dni?: string | null;
  domicilio?: string | null;
  iva: string;
  empresa?: { nombre: string; cuit?: string | null } | null;
  ordenes: { id: string; numero: number; estado: string; fechaRecepcion: string; maquina?: { nombre: string } | null; marca?: { nombre: string } | null; modelo?: { nombre: string } | null }[];
  presupuestos: { id: string; numero: number; fecha: string; estado: string; estadoCobro: string; total: number; cobrado: number; saldo: number; orden?: { numero: number } | null }[];
  cobranzas: { id: string; fecha: string; importe: number; formaPago: string; descripcion?: string | null; caja?: { nombre: string } | null; presupuesto?: { numero: number } | null }[];
  totalPresupuestado: number;
  totalCobrado: number;
  saldoPendiente: number;
}

const estadoOTColors: Record<string, string> = {
  RECIBIDO: "border-gray-200 text-gray-500",
  PARA_REVISAR: "border-amber-200 text-amber-600 bg-amber-50",
  EN_REVISION: "border-blue-200 text-blue-600 bg-blue-50",
  REVISADO: "border-orange-200 text-orange-600 bg-orange-50",
  PARA_PRESUPUESTAR: "border-red-600 text-red-600 bg-red-50",
  PRESUPUESTADO: "border-purple-200 text-purple-600 bg-purple-50",
  APROBADO: "border-emerald-600 text-emerald-600 bg-emerald-50",
  EN_REPARACION: "border-blue-400 text-blue-700 bg-blue-50",
  REPARADO: "border-emerald-400 text-emerald-700 bg-emerald-50",
  PARA_ENTREGAR: "border-cyan-400 text-cyan-700 bg-cyan-50",
  ENTREGADO_REALIZADO: "border-emerald-600 text-emerald-800 bg-emerald-100 font-bold",
  ENTREGADO_SIN_REALIZAR: "border-orange-400 text-orange-800 bg-orange-100",
  RECHAZADO: "border-red-800 text-red-800 bg-red-100",
};

function formatNumero(numero: number, fecha: string) {
  const year = new Date(fecha).getFullYear();
  return `${year}-${numero.toString().padStart(5, "0")}`;
}

export default function ClienteDetallePage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const params = useParams();
  const id = params.id as string;
  const [cliente, setCliente] = useState<ClienteDetalle | null>(null);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState<"ots" | "pptos" | "cobranzas" | "cuenta">("ots");

  useEffect(() => {
    if (status === "unauthenticated") router.push("/login");
  }, [status, router]);

  useEffect(() => {
    if (id) {
      fetch(`/api/clientes/${id}`)
        .then((r) => r.json())
        .then((data) => { setCliente(data); setLoading(false); })
        .catch(() => setLoading(false));
    }
  }, [id]);

  if (status === "loading" || loading) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center font-black uppercase tracking-[0.3em] text-gray-400 animate-pulse">
        Sincronizando Expediente de Cliente...
      </div>
    );
  }

  if (!cliente || (cliente as { error?: string }).error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-10">
        <div className="text-center space-y-4">
           <User size={64} className="mx-auto text-gray-300" />
           <p className="text-red-600 font-black uppercase tracking-widest text-xl italic">ENTIDAD NO IDENTIFICADA EN BASE DE DATOS</p>
           <Link href="/clientes" className="text-xs font-black text-gray-400 hover:text-red-600 uppercase transition-colors underline">[ VOLVER AL MAESTRO ]</Link>
