                 {cliente.email && (
                   <a href={`mailto:${cliente.email}`} className="flex items-center gap-4 p-5 bg-blue-50 rounded-2xl border-2 border-blue-100 text-blue-700 hover:bg-blue-100 transition-all">
                      <Mail size={24} />
