                      </div>
                   </a>
                 )}
              </div>
           </section>

           {/* CARD FINANCIERO EXPRESS */}
           <section className="bg-white rounded-3xl shadow-2xl border-2 border-gray-100 overflow-hidden divide-y-2 divide-gray-100">
