"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import Link from "next/link";
import {
  Settings, Trash2, Plus, Users, Shield, Wrench,
  ArrowLeft, Eye, EyeOff, Check, X, Edit2,
  AlertCircle, Lock, HardHat
} from "lucide-react";

interface Usuario {
  id: string;
  nombre: string;
  email: string;
  rol: string;
  activo: boolean;
  createdAt: string;
}

const ROL_LABELS: Record<string, string> = {
  ADMIN: "Administrador de Sistema",
  TECNICO: "Operador Técnico",
  CAJA: "Control de Tesorería",
  VENTAS: "Gestión Comercial",
};

const ROL_COLORS: Record<string, string> = {
  ADMIN: "border-red-600 text-red-600 bg-red-50/50",
  TECNICO: "border-gray-900 text-gray-900 bg-gray-50",
  CAJA: "border-emerald-600 text-emerald-600 bg-emerald-50/50",
  VENTAS: "border-amber-600 text-amber-600 bg-amber-50/50",
};

type ActiveTab = "accesorios" | "usuarios";

export default function ConfiguracionPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [activeTab, setActiveTab] = useState<ActiveTab>("accesorios");

  // Accesorios
  const [accesorios, setAccesorios] = useState<{ id: string; nombre: string }[]>([]);
  const [nuevoAcc, setNuevoAcc] = useState("");
  const [loadingAcc, setLoadingAcc] = useState(false);

  // Usuarios
  const [usuarios, setUsuarios] = useState<Usuario[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(false);
  const [showInactivos, setShowInactivos] = useState(false);

  // Formulario nuevo/editar usuario
  const [editingUser, setEditingUser] = useState<Usuario | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [uNombre, setUNombre] = useState("");
  const [uEmail, setUEmail] = useState("");
  const [uPassword, setUPassword] = useState("");
  const [uRol, setURol] = useState("TECNICO");
  const [uActivo, setUActivo] = useState(true);
  const [showPass, setShowPass] = useState(false);
  const [guardandoUser, setGuardandoUser] = useState(false);
  const [errorUser, setErrorUser] = useState("");

  useEffect(() => {
    if (status === "unauthenticated") router.push("/login");
  }, [status, router]);

  useEffect(() => {
    if (status === "authenticated") {
      cargarAccesorios();
      cargarUsuarios();
    }
  }, [status]);

  const cargarAccesorios = async () => {
    setLoadingAcc(true);
    const res = await fetch("/api/accesorios");
    if (res.ok) setAccesorios(await res.json());
    setLoadingAcc(false);
  };

  const cargarUsuarios = async () => {
    setLoadingUsers(true);
    const res = await fetch("/api/usuarios");
    if (res.ok) setUsuarios(await res.json());
    setLoadingUsers(false);
  };

  // --- Accesorios ---
  const addAcc = async () => {
    if (!nuevoAcc.trim()) return;
    const res = await fetch("/api/accesorios", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ nombre: nuevoAcc.trim().toUpperCase() }),
    });
    if (res.ok) {
      const data = await res.json();
      setAccesorios((prev) => [...prev, data]);
      setNuevoAcc("");
    }
  };

  const removeAcc = async (id: string) => {
    await fetch(`/api/accesorios/${id}`, { method: "DELETE" });
    setAccesorios((prev) => prev.filter((x) => x.id !== id));
  };

  // --- Usuarios ---
  const abrirNuevo = () => {
    setEditingUser(null);
    setUNombre(""); setUEmail(""); setUPassword(""); setURol("TECNICO"); setUActivo(true);
    setErrorUser("");
    setShowForm(true);
  };

  const abrirEditar = (u: Usuario) => {
    setEditingUser(u);
    setUNombre(u.nombre); setUEmail(u.email); setUPassword(""); setURol(u.rol); setUActivo(u.activo);
    setErrorUser("");
    setShowForm(true);
  };

  const guardarUsuario = async () => {
    if (!uNombre.trim() || !uEmail.trim()) { setErrorUser("Nombre y email solicitados"); return; }
    if (!editingUser && !uPassword.trim()) { setErrorUser("Contraseña requerida"); return; }
    setGuardandoUser(true);
    setErrorUser("");

    const body: Record<string, unknown> = { nombre: uNombre.toUpperCase(), email: uEmail.toLowerCase(), rol: uRol, activo: uActivo };
    if (uPassword) body.password = uPassword;

    const url = editingUser ? `/api/usuarios/${editingUser.id}` : "/api/usuarios";
    const method = editingUser ? "PATCH" : "POST";

    const res = await fetch(url, {
      method,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });

    if (res.ok) {
      setShowForm(false);
      cargarUsuarios();
    } else {
      const err = await res.json();
      setErrorUser(err.error || "Error al guardar usuario");
    }
    setGuardandoUser(false);
  };

  const toggleActivo = async (u: Usuario) => {
    const res = await fetch(`/api/usuarios/${u.id}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ activo: !u.activo }),
    });
    if (res.ok) cargarUsuarios();
  };

  const usuariosFiltrados = usuarios.filter((u) => showInactivos || u.activo);

  if (status === "loading") return (
    <div className="flex flex-col items-center justify-center p-40">
      <div className="w-12 h-1 bg-red-600 rounded-full animate-pulse mb-4" />
      <div className="text-gray-400 font-medium text-sm animate-pulse">Cargando configuración...</div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <Link href="/dashboard" className="p-2 text-gray-400 hover:text-red-600 hover:bg-gray-50 rounded-xl transition-all">
              <ArrowLeft size={24} />
            </Link>
            <div>
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Mantenimiento</p>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Configuración del Sistema</h1>
            </div>
          </div>
          <div className="p-2 bg-gray-50 rounded-xl border border-gray-100 hidden sm:block">
            <Settings size={28} className="text-red-600" />
          </div>
        </div>
      </header>

      <div className="bg-white border-b border-gray-200 sticky top-20 z-30">
        <div className="max-w-7xl mx-auto px-6 flex gap-8">
          {[
            { key: "accesorios" as ActiveTab, label: "Componentes", icon: <Wrench size={18} /> },
            { key: "usuarios" as ActiveTab, label: "Gestión de Personal", icon: <Users size={18} /> },
          ].map((tab) => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`flex items-center gap-2 px-6 py-4 text-xs font-bold border-b-2 transition-all uppercase tracking-wider ${
                activeTab === tab.key
                  ? "border-red-600 text-red-600"
                  : "border-transparent text-gray-400 hover:text-gray-600"
              }`}
            >
              {tab.icon}
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="flex-1 max-w-7xl mx-auto px-6 py-12 w-full space-y-12">

        {activeTab === "accesorios" && (
          <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
            <div className="p-8 border-b border-gray-100 bg-gray-50/20 flex flex-col sm:flex-row items-center justify-between gap-6">
                <div>
                  <h2 className="text-lg font-bold text-gray-900 uppercase">Catálogo de Accesorios</h2>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Nomenclador para recepción de equipos</p>
                </div>
                <div className="flex gap-2 w-full sm:w-auto">
                  <input
                    type="text"
                    value={nuevoAcc}
                    onChange={(e) => setNuevoAcc(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && addAcc()}
                    className="flex-1 sm:w-64 px-4 py-2.5 bg-white border border-gray-200 rounded-xl text-sm font-bold outline-none focus:border-red-600 transition-all uppercase"
                    placeholder="Nuevo item..."
                  />
                  <button
                    onClick={addAcc}
                    className="bg-red-600 text-white px-5 py-2.5 rounded-xl text-xs font-bold hover:bg-red-700 transition-all shadow-md shadow-red-600/10 flex items-center gap-2"
                  >
                    <Plus size={18} /> Añadir
                  </button>
                </div>
            </div>

            <div className="p-8">
              {loadingAcc ? (
                <div className="p-10 text-center text-gray-400 text-xs font-bold animate-pulse">Cargando catálogo...</div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                  {accesorios.map((a) => (
                    <div
                      key={a.id}
                      className="group flex items-center justify-between bg-gray-50/50 border border-gray-100 px-4 py-3 rounded-xl hover:bg-white hover:border-red-100 transition-all"
                    >
                      <div className="flex items-center gap-3 min-w-0">
                         <div className="w-1.5 h-1.5 rounded-full bg-red-600" />
                         <span className="text-xs font-bold text-gray-600 uppercase truncate">{a.nombre}</span>
                      </div>
                      <button
                        onClick={() => removeAcc(a.id)}
                        className="p-1.5 text-gray-200 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}
                  {accesorios.length === 0 && (
                    <div className="col-span-full p-16 text-center border-2 border-dashed border-gray-100 rounded-2xl italic text-gray-400 text-sm">
                        No se registran componentes en el catálogo
                    </div>
                  )}
                </div>
              )}
            </div>
          </section>
        )}

        {activeTab === "usuarios" && (
          <div className="space-y-12">
            <div className="flex flex-col sm:flex-row items-end sm:items-center justify-between gap-6">
              <div className="space-y-1">
                <h2 className="text-xl font-bold text-gray-900 uppercase">Gestión de Personal</h2>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Base de datos de usuarios y permisos</p>
              </div>
              <div className="flex items-center gap-4">
                <label className="flex items-center gap-2 text-[10px] font-bold text-gray-400 cursor-pointer uppercase bg-white px-4 py-2 rounded-xl shadow-sm border border-gray-200">
                  <input
                    type="checkbox"
                    checked={showInactivos}
                    onChange={(e) => setShowInactivos(e.target.checked)}
                    className="w-4 h-4 rounded-md border-gray-200 text-red-600"
                  />
                  Mostrar inactivos
                </label>
                <button
                  onClick={abrirNuevo}
                  className="bg-gray-900 text-white px-5 py-2.5 rounded-xl text-xs font-bold hover:bg-red-600 transition-all shadow-lg shadow-gray-900/10 flex items-center gap-2"
                >
                  <Plus size={18} /> Nuevo Operador
                </button>
              </div>
            </div>

            {showForm && (
              <div className="bg-white border-2 border-red-600/10 rounded-3xl p-8 shadow-xl animate-in zoom-in duration-300">
                <div className="flex items-center gap-4 mb-8">
                   <div className="bg-red-600/10 p-3 rounded-xl text-red-600">
                      <HardHat size={24} />
                   </div>
                   <h3 className="text-lg font-bold text-gray-900 uppercase">
                      {editingUser ? `Editar Usuario: ${editingUser.nombre}` : "Alta de Nuevo Usuario"}
                   </h3>
                </div>

                {errorUser && (
                  <div className="bg-red-50 text-red-700 px-4 py-3 rounded-xl text-xs font-bold mb-8 flex items-center gap-2">
                    <AlertCircle size={16} /> {errorUser}
                  </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block ml-1">Nombre Completo *</label>
                    <input
                      type="text"
                      value={uNombre}
                      onChange={(e) => setUNombre(e.target.value)}
                      className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none transition-all uppercase"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block ml-1">Email Acceso *</label>
                    <input
                      type="email"
                      value={uEmail}
                      onChange={(e) => setUEmail(e.target.value)}
                      className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none transition-all"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block ml-1">
                      {editingUser ? "Nueva Clave (Opcional)" : "Password *"}
                    </label>
                    <div className="relative">
                      <input
                        type={showPass ? "text" : "password"}
                        value={uPassword}
                        onChange={(e) => setUPassword(e.target.value)}
                        className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none transition-all"
                      />
                      <button
                        type="button"
                        onClick={() => setShowPass(!showPass)}
                        className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-300 hover:text-red-600"
                      >
                        {showPass ? <EyeOff size={20} /> : <Eye size={20} />}
                      </button>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block ml-1">Jerarquía / Rol</label>
                    <select
                      value={uRol}
                      onChange={(e) => setURol(e.target.value)}
                      className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-xs font-bold outline-none uppercase appearance-none cursor-pointer"
                    >
                      {Object.entries(ROL_LABELS).map(([val, label]) => (
                        <option key={val} value={val}>{label}</option>
                      ))}
                    </select>
                  </div>
                  {editingUser && (
                    <div className="space-y-2 text-center">
                      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block mb-2">Estado de Cuenta</label>
                      <button
                        onClick={() => setUActivo(!uActivo)}
                        className={`px-6 py-2.5 rounded-xl text-[10px] font-bold border-2 transition-all uppercase tracking-widest ${uActivo ? "bg-emerald-50 border-emerald-100 text-emerald-700 shadow-sm" : "bg-red-50 border-red-100 text-red-700 shadow-sm"}`}
                      >
                        {uActivo ? "CUENTA ACTIVA" : "CUENTA INACTIVA / BLOQUEADA"}
                      </button>
                    </div>
                  )}
                </div>

                <div className="flex flex-col sm:flex-row gap-4 mt-10 pt-6 border-t border-gray-50">
                  <button
                    onClick={guardarUsuario}
                    disabled={guardandoUser}
                    className="flex-1 bg-red-600 text-white px-6 py-3.5 rounded-xl text-sm font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-600/20 disabled:opacity-50"
                  >
                    {guardandoUser ? "Guardando..." : editingUser ? "Actualizar Datos" : "Confirmar Alta"}
                  </button>
                  <button
                    onClick={() => setShowForm(false)}
                    className="px-6 py-3.5 bg-white border border-gray-200 text-gray-400 rounded-xl text-sm font-bold hover:bg-gray-50"
                  >
                    Cancelar
                  </button>
                </div>
              </div>
            )}

            <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
              {loadingUsers ? (
                <div className="p-16 text-center text-gray-400 text-xs font-bold animate-pulse italic">Cargando base de datos...</div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b border-gray-100 text-gray-400 uppercase text-[10px] font-bold tracking-widest bg-gray-50/50">
                        <th className="text-left px-8 py-5">Nombre / Usuario</th>
                        <th className="text-left px-8 py-5">Email</th>
                        <th className="text-left px-8 py-5">Rol / Jerarquía</th>
                        <th className="text-left px-8 py-5">Estado</th>
                        <th className="text-right px-8 py-5">Sistema</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                      {usuariosFiltrados.map((u) => (
                        <tr key={u.id} className={`hover:bg-gray-50/30 group transition-all ${!u.activo ? "opacity-40 grayscale" : ""}`}>
                          <td className="px-8 py-6">
                            <div className="flex items-center gap-4">
                              <div className="w-10 h-10 rounded-lg bg-gray-900 flex items-center justify-center text-white font-bold text-sm shadow-sm">
                                {u.nombre.charAt(0).toUpperCase()}
                              </div>
                              <div>
                                  <div className="font-bold text-gray-900 uppercase text-sm leading-tight flex items-center gap-2">
                                    {u.nombre}
                                    {u.id === (session?.user as { id?: string })?.id && (
                                       <span className="text-[8px] bg-red-600 text-white px-2 py-0.5 rounded-full font-bold">USTED</span>
                                    )}
                                  </div>
                                  <div className="text-[9px] text-gray-400 font-bold uppercase tracking-widest mt-1">ID: {u.id.substring(0,8)}</div>
                              </div>
                            </div>
                          </td>
                          <td className="px-8 py-6 text-gray-500 font-medium text-xs">
                             {u.email}
                          </td>
                          <td className="px-8 py-6">
                             <span className={`px-3 py-1.5 rounded-lg text-[9px] font-bold uppercase tracking-widest border ${ROL_COLORS[u.rol] || "border-gray-100 text-gray-400"}`}>
                               {ROL_LABELS[u.rol] || u.rol}
                             </span>
                          </td>
                          <td className="px-8 py-6">
                             <div className="flex items-center gap-2">
                                <div className={`w-2 h-2 rounded-full ${u.activo ? "bg-emerald-500 animate-pulse" : "bg-red-500"}`} />
                                <span className="text-[10px] font-bold uppercase text-gray-600">{u.activo ? "Activo" : "Bloqueado"}</span>
                             </div>
                          </td>
                          <td className="px-8 py-6 text-right">
                            <div className="flex items-center justify-end gap-2">
                              <button
                                onClick={() => abrirEditar(u)}
                                className="p-2 text-gray-300 hover:text-red-600 hover:bg-gray-100 rounded-lg transition-all"
                              >
                                <Edit2 size={18} />
                              </button>
                              <button
                                onClick={() => toggleActivo(u)}
                                disabled={u.id === (session?.user as { id?: string })?.id}
                                className={`p-2 rounded-lg transition-all disabled:opacity-20 ${
                                  u.activo ? "text-gray-200 hover:text-red-700 hover:bg-red-50" : "text-gray-200 hover:text-emerald-700 hover:bg-emerald-50"
                                }`}
                              >
                                {u.activo ? <X size={18} /> : <Check size={18} />}
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import { getServerSession } from "next-auth";
import { redirect } from "next/navigation";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { 
  Wrench, 
  CheckCircle, 
  AlertTriangle, 
  MessageSquare, 
  TrendingUp, 
  TrendingDown, 
  DollarSign, 
  BarChart2,
  Clock,
  ExternalLink,
  ChevronRight,
  Target,
  Bell
} from "lucide-react";
import Link from "next/link";
import { GlobalNoteForm } from "./GlobalNoteForm";
import { StatusBadge } from "@/components/ui/StatusBadge";
import { FinanceChart } from "@/components/ui/FinanceChart";
import { Card, StatCard } from "@/components/ui/Card";

export default async function DashboardPage() {
  const session = await getServerSession(authOptions);

  if (!session) {
    redirect("/login");
  }

  const userId = (session.user as any)?.id;
  const hoy = new Date();

  // 1. Tareas Asignadas
  const misTareas = await prisma.tarea.findMany({
    where: { usuarioId: userId, estado: { not: "COMPLETADA" } },
    orderBy: [{ vencimiento: "asc" }, { prioridad: "desc" }]
  });

  // 2. Taller: OTs Activas
  const otsEnProceso = await prisma.ordenTrabajo.findMany({
    where: { estado: { notIn: ["ENTREGADO_REALIZADO", "ENTREGADO_SIN_REALIZAR", "RECHAZADO"] } },
    include: { cliente: { select: { nombre: true } } },
    orderBy: { fechaRecepcion: "desc" }
  });

  // 3. Seguimientos y Alertas
  const seguimientos = await (prisma as any).nota.findMany({
    where: { esSeguimiento: true, orden: { estado: { notIn: ["ENTREGADO_REALIZADO", "ENTREGADO_SIN_REALIZAR", "RECHAZADO"] } } },
    include: { orden: { select: { numero: true, id: true, cliente: { select: { nombre: true } } } } },
    orderBy: { fecha: "desc" }
  });

  // 5. Resumen Financiero Mes Actual
  const inicioMes = new Date(hoy.getFullYear(), hoy.getMonth(), 1);
  const finMes = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0, 23, 59, 59);

  const movsCaja = await prisma.movimientoCaja.aggregate({
    where: { fecha: { gte: inicioMes, lte: finMes } },
    _sum: { ingreso: true, egreso: true }
  });
  const mesIngresos = movsCaja._sum.ingreso || 0;
  const mesEgresos = movsCaja._sum.egreso || 0;
  const mesBalance = mesIngresos - mesEgresos;

  // 7. Gráfico: últimos 30 días
  const hace30 = new Date(hoy);
  hace30.setDate(hoy.getDate() - 29);
  hace30.setHours(0, 0, 0, 0);

  const movs30 = await prisma.movimientoCaja.findMany({
    where: { fecha: { gte: hace30 } },
    select: { fecha: true, ingreso: true, egreso: true },
    orderBy: { fecha: "asc" },
  });

  const dayMap = new Map<string, { ingresos: number; egresos: number }>();
  for (let i = 0; i < 30; i++) {
    const d = new Date(hace30);
    d.setDate(hace30.getDate() + i);
    const key = `${String(d.getDate()).padStart(2, "0")}/${String(d.getMonth() + 1).padStart(2, "0")}`;
    dayMap.set(key, { ingresos: 0, egresos: 0 });
  }
  for (const m of movs30) {
    const d = new Date(m.fecha);
    const key = `${String(d.getDate()).padStart(2, "0")}/${String(d.getMonth() + 1).padStart(2, "0")}`;
    const existing = dayMap.get(key);
    if (existing) {
      existing.ingresos += m.ingreso || 0;
      existing.egresos += m.egreso || 0;
    }
  }
  const chartData = Array.from(dayMap.entries()).map(([fecha, v]) => ({
    fecha,
    ingresos: v.ingresos,
    egresos: v.egresos,
  }));

  const notaGlobal = await (prisma as any).configuracion.findUnique({
    where: { clave: "NOTA_GLOBAL" }
  });

  return (
    <div className="p-6 lg:p-10 space-y-10 bg-gray-50 font-sans">

      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 border-b border-gray-200 pb-8">
        <div>
           <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1">Panel de Control</p>
           <h1 className="text-3xl lg:text-4xl font-bold text-gray-900 tracking-tight">
              Escritorio <span className="text-red-600">Administrativo</span>
           </h1>
        </div>

        <div className="flex items-center gap-4">
           <div className="bg-white border border-gray-200 px-5 py-3 rounded-xl shadow-sm flex items-center gap-4">
              <Clock size={20} className="text-red-600" />
              <div>
                 <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider">Fecha y Hora Actual</p>
                 <span className="text-sm font-bold text-gray-900">
                    {hoy.toLocaleDateString('es-AR')} — {hoy.toLocaleTimeString('es-AR', { hour: '2-digit', minute: '2-digit' })}
                 </span>
              </div>
           </div>
        </div>
      </header>

      {/* Resumen Financiero */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <StatCard 
          label="Ingresos del Mes"
          value={`$${mesIngresos.toLocaleString("es-AR")}`}
          icon={<TrendingUp size={20} />}
          color="emerald"
        />
        <StatCard 
          label="Egresos del Mes"
          value={`$${mesEgresos.toLocaleString("es-AR")}`}
          icon={<TrendingDown size={20} />}
          color="rose"
        />
        <StatCard 
          label="Balance de Caja"
          value={`$${mesBalance.toLocaleString("es-AR")}`}
          icon={<DollarSign size={20} />}
          color={mesBalance >= 0 ? "primary" : "rose"}
          trend={{ value: "Saldo Neto", positive: mesBalance >= 0 }}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

         {/* Gráfico */}
         <div className="lg:col-span-8">
            <Card 
              title="Flujo de Operaciones" 
              subtitle="Movimientos de los últimos 30 días"
              icon={<BarChart2 size={20} className="text-red-600" />}
              action={<Link href="/cajas" className="text-xs font-bold text-red-600 hover:underline flex items-center gap-1">Ver todos <ChevronRight size={14} /></Link>}
              className="h-full rounded-2xl shadow-sm border border-gray-200"
            >
              <div className="py-4">
                <FinanceChart data={chartData} />
              </div>
            </Card>
         </div>

         {/* Alertas */}
         <div className="lg:col-span-4 h-full">
            <Card 
              title="Alertas de Seguimiento" 
              icon={<Bell size={20} className="text-red-600" />}
              className="h-full border border-gray-200 rounded-2xl shadow-sm"
            >
              <div className="space-y-4">
                {(seguimientos as any[]).length === 0 ? (
                  <div className="text-center py-12">
                     <AlertTriangle size={40} className="mx-auto mb-2 text-gray-200" />
                     <p className="text-xs text-gray-400 font-medium font-sans">Sin alertas pendientes</p>
                  </div>
                ) : (
                  (seguimientos as any[]).map(s => (
                    <Link key={s.id} href={`/ordenes/${s.orden.id}`} className="block p-4 rounded-xl border border-gray-100 bg-white hover:border-red-600 hover:shadow-md transition-all group">
                      <div className="text-[10px] font-bold text-red-600 mb-2 uppercase tracking-wider flex items-center justify-between">
                         <span>OT #{s.orden.numero} — {s.orden.cliente.nombre}</span>
                         <ExternalLink size={12} />
                      </div>
                      <p className="text-xs text-gray-700 leading-relaxed font-medium">"{s.texto}"</p>
                    </Link>
                  ))
                )}
              </div>
            </Card>
         </div>

      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-8">

        {/* Tareas */}
        <Card 
          title="Tareas Pendientes" 
          icon={<Target size={20} className="text-gray-900" />}
          action={<span className="text-[10px] font-bold bg-gray-900 text-white px-3 py-1 rounded-md">{misTareas.length}</span>}
          className="rounded-2xl shadow-sm border border-gray-200"
        >
          <div className="space-y-3 max-h-[400px] overflow-y-auto pr-1">
            {misTareas.length === 0 ? (
              <div className="text-center py-12">
                <CheckCircle size={40} className="mx-auto mb-2 text-gray-200" />
                <p className="text-xs text-gray-400 font-medium">Cronograma al día</p>
              </div>
            ) : (
              misTareas.map(t => {
                const isVencida = t.vencimiento && t.vencimiento < hoy;
                return (
                  <Link key={t.id} href="/tareas" className="block">
                    <div className={`p-4 rounded-xl border transition-all ${isVencida ? 'border-red-200 bg-red-50' : 'border-gray-50 bg-gray-50/50 hover:bg-white hover:border-red-200'}`}>
                      <div className="flex justify-between items-start mb-2">
                        <StatusBadge status={isVencida ? 'URGENTE' : t.prioridad} />
                        {t.vencimiento && <span className="text-[9px] font-bold text-gray-400">{t.vencimiento.toLocaleDateString('es-AR')}</span>}
                      </div>
                      <p className="text-xs font-bold text-gray-900 uppercase leading-snug">{t.descripcion}</p>
                    </div>
                  </Link>
                );
              })
            )}
          </div>
        </Card>

        {/* Taller */}
        <Card 
          title="Equipos en Taller" 
          icon={<Wrench size={20} className="text-gray-900" />}
          action={<span className="text-[10px] font-bold border border-gray-200 px-3 py-1 rounded-md">{otsEnProceso.length}</span>}
          className="rounded-2xl shadow-sm border border-gray-200"
        >
          <div className="space-y-3 max-h-[400px] overflow-y-auto pr-1">
            {otsEnProceso.length === 0 ? (
               <div className="text-center py-12">
                  <p className="text-xs text-gray-400 font-medium">Sin equipos en reparación</p>
               </div>
            ) : (
              otsEnProceso.map(ot => (
                <Link key={ot.id} href={`/ordenes/${ot.id}`} className="block p-4 rounded-xl bg-white border border-gray-100 hover:border-red-600 transition-all shadow-sm">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-sm font-bold text-red-600 uppercase">OT #{ot.numero}</span>
                    <StatusBadge status={ot.estado} />
                  </div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase tracking-tight truncate border-b border-gray-50 pb-2 mb-2">{ot.cliente.nombre}</div>
                  {(ot as any).fechaEstimadaEntrega && (
                    <div className="flex items-center gap-2 text-[9px] font-bold text-gray-400 uppercase">
                      Entrega: 
                      <span className={`px-1.5 py-0.5 rounded ${(ot as any).fechaEstimadaEntrega < hoy ? "bg-red-600 text-white" : "bg-gray-100 text-gray-700"}`}>
                        {(ot as any).fechaEstimadaEntrega.toLocaleDateString("es-AR")}
                      </span>
                    </div>
                  )}
                </Link>
              ))
            )}
          </div>
        </Card>

        {/* Comunicaciones */}
        <Card 
          title="Avisos del Equipo" 
          icon={<MessageSquare size={20} className="text-gray-900" />}
          className="rounded-2xl shadow-sm border border-gray-200"
        >
          <div className="p-4 bg-gray-50 rounded-xl border border-gray-100 border-dashed">
            <GlobalNoteForm initialNote={notaGlobal?.valor || ""} />
          </div>
          <p className="text-[9px] text-gray-400 font-medium text-center mt-6 uppercase tracking-widest">ServiNOA © {new Date().getFullYear()}</p>
        </Card>

      </div>
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import Link from "next/link";
import { 
  Trash2, ArrowLeft, Plus, Receipt, 
  User, Calendar, Search, Activity, 
  Filter, ArrowUpRight
} from "lucide-react";
import { ConfirmDialog } from "@/components/ui/ConfirmDialog";
import { Drawer } from "@/components/ui/Drawer";

interface Gasto {
  id: string;
  tipo: string;
  fecha: string;
  descripcion: string;
  importe: number;
  formaPago: string;
  comprobante?: string | null;
  empleado?: string | null;
  desde?: string | null;
  hasta?: string | null;
  usuario: { nombre: string };
  caja?: { nombre: string } | null;
  proveedor?: { nombre: string } | null;
}

interface Proveedor { id: string; nombre: string; }
interface Caja { id: string; nombre: string; }

const FORMAS_PAGO = ["EFECTIVO", "TRANSFERENCIA", "CHEQUE", "TARJETA", "MERCADO PAGO", "OTRO"];

export default function GastosPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [gastos, setGastos] = useState<Gasto[]>([]);
  const [loading, setLoading] = useState(true);
  const [mostrarForm, setMostrarForm] = useState(false);

  // Form
  const [tipo, setTipo] = useState<"GASTO_VARIOS" | "SUELDO">("GASTO_VARIOS");
  const [descripcion, setDescripcion] = useState("");
  const [importe, setImporte] = useState("");
  const [formaPago, setFormaPago] = useState("EFECTIVO");
  const [cajaId, setCajaId] = useState("");
  const [proveedorId, setProveedorId] = useState("");
  const [comprobante, setComprobante] = useState("");
  const [empleado, setEmpleado] = useState("");
  const [desde, setDesde] = useState("");
  const [hasta, setHasta] = useState("");
  const [cajas, setCajas] = useState<Caja[]>([]);
  const [proveedores, setProveedores] = useState<Proveedor[]>([]);
  const [guardando, setGuardando] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);
  const [eliminando, setEliminando] = useState(false);

  const [searchTerm, setSearchTerm] = useState("");

  useEffect(() => {
    if (status === "unauthenticated") router.push("/login");
  }, [status, router]);

  const cargar = () => {
    fetch("/api/gastos").then((r) => r.json()).then((d) => { setGastos(d); setLoading(false); }).catch(() => setLoading(false));
  };

  useEffect(() => { cargar(); }, []);

  useEffect(() => {
    fetch("/api/cajas").then((r) => r.json()).then((d) => { setCajas(d); if (d.length > 0) setCajaId(d[0].id); });
    fetch("/api/proveedores").then((r) => r.json()).then(setProveedores);
  }, []);

  const eliminarGasto = async (id: string) => {
    setEliminando(true);
    await fetch(`/api/gastos/${id}`, { method: "DELETE" });
    setEliminando(false);
    setConfirmDelete(null);
    cargar();
  };

  const guardar = async () => {
    if (!importe || !cajaId) return;
    if (tipo === "GASTO_VARIOS" && !descripcion) return;
    if (tipo === "SUELDO" && !empleado) return;
    setGuardando(true);

    await fetch("/api/gastos", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        tipo,
        descripcion: tipo === "SUELDO" ? `SUELDO ${empleado.toUpperCase()}` : descripcion.toUpperCase(),
        importe,
        formaPago,
        cajaId,
        usuarioId: (session?.user as { id?: string })?.id,
        proveedorId: proveedorId || null,
        comprobante: comprobante.toUpperCase() || null,
        empleado: tipo === "SUELDO" ? empleado.toUpperCase() : null,
        desde: desde || null,
        hasta: hasta || null,
      }),
    });

    setMostrarForm(false);
    setImporte(""); setDescripcion(""); setComprobante(""); setEmpleado(""); setDesde(""); setHasta(""); setProveedorId("");
    setGuardando(false);
    cargar();
  };

  const totalDelMes = () => {
    const ahora = new Date();
    return gastos
      .filter((g) => {
        const f = new Date(g.fecha);
        return f.getMonth() === ahora.getMonth() && f.getFullYear() === ahora.getFullYear();
      })
      .reduce((sum, g) => sum + g.importe, 0);
  };

  if (status === "loading" || loading) return (
    <div className="flex flex-col items-center justify-center p-40">
      <div className="w-12 h-1 bg-red-600 rounded-full animate-pulse mb-4" />
      <div className="text-gray-400 font-medium text-sm animate-pulse">Cargando gastos...</div>
    </div>
  );

  const filteredGastos = gastos.filter(g => 
    g.descripcion.toLowerCase().includes(searchTerm.toLowerCase()) ||
    g.empleado?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    g.proveedor?.nombre.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <Link href="/dashboard" className="p-2 text-gray-400 hover:text-red-600 hover:bg-gray-50 rounded-xl transition-all">
              <ArrowLeft size={24} />
            </Link>
            <div>
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Tesorería</p>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Control de Gastos</h1>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden md:block bg-red-50 px-4 py-2 rounded-xl border border-red-100">
                <p className="text-[9px] font-bold text-red-600 uppercase tracking-wider mb-0.5">Total del Mes</p>
                <p className="text-lg font-bold tabular-nums text-red-700">
                   ${totalDelMes().toLocaleString("es-AR", { minimumFractionDigits: 2 })}
                </p>
             </div>
             <button
              onClick={() => setMostrarForm(true)}
              className="bg-red-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-600/10 flex items-center gap-2"
            >
              <Plus size={18} /> Registrar Gasto
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-6xl mx-auto px-6 py-10 w-full space-y-8">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-gray-200 shadow-sm">
           <div className="relative w-full max-w-lg">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
              <input 
                type="text" 
                placeholder="Buscar por descripción, empleado o proveedor..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-12 pr-4 py-2.5 bg-gray-50 border border-transparent focus:border-red-600 rounded-xl text-sm font-medium outline-none transition-all"
              />
           </div>
           <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider bg-gray-50 px-3 py-2 rounded-lg border border-gray-100 italic">
              {filteredGastos.length} gastos encontrados
           </div>
        </div>

        <div className="space-y-4">
          {filteredGastos.map((g, idx) => (
            <div 
              key={g.id} 
              className="group bg-white p-6 rounded-2xl border border-gray-200 hover:shadow-md transition-all flex items-center gap-6"
            >
              <div className="w-12 h-12 rounded-xl bg-red-50 flex items-center justify-center text-red-600 shrink-0">
                <Receipt size={24} />
              </div>

              <div className="flex-1 min-w-0">
                <div className="flex items-start justify-between gap-4">
                  <div>
                    <p className="text-base font-bold text-gray-900 group-hover:text-red-600 transition-colors uppercase leading-tight">
                      {g.descripcion}
                    </p>
                    <div className="flex flex-wrap items-center gap-3 mt-1.5">
                       <span className="text-[10px] font-bold text-gray-400 uppercase bg-gray-50 px-2 py-0.5 rounded border border-gray-100">
                          {new Date(g.fecha).toLocaleDateString("es-AR")}
                       </span>
                       <span className={`px-2 py-0.5 rounded text-[9px] font-bold uppercase tracking-wider border ${g.tipo === "SUELDO" ? "border-gray-900 text-gray-900" : "border-red-100 text-red-600 bg-red-50"}`}>
                          {g.tipo === "SUELDO" ? "Sueldo" : "Gasto Varios"}
                       </span>
                       {g.proveedor && <span className="text-[10px] font-bold text-gray-400 uppercase">Prov: {g.proveedor.nombre}</span>}
                       {g.caja && <span className="text-[10px] font-bold text-emerald-600 uppercase italic">Caja: {g.caja.nombre}</span>}
                    </div>
                  </div>

                  <div className="text-right">
                     <p className="text-xl font-bold tabular-nums text-red-600">
                        ${g.importe.toLocaleString("es-AR", { minimumFractionDigits: 2 })}
                     </p>
                     <div className="text-[9px] font-bold text-gray-400 uppercase mt-1">
                        {g.usuario?.nombre}
                     </div>
                  </div>
                </div>

                <div className="mt-4 pt-4 border-t border-gray-50 flex items-center justify-between">
                   <div className="text-[9px] font-bold text-gray-300 uppercase tracking-widest tabular-nums italic">
                      ID: {g.id.substring(0,8).toUpperCase()}
                   </div>
                   <button
                      onClick={() => setConfirmDelete(g.id)}
                      className="p-1 px-2 text-gray-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all opacity-0 group-hover:opacity-100 flex items-center gap-1 text-[10px] font-bold uppercase"
                    >
                      <Trash2 size={14} /> Eliminar
                    </button>
                </div>
              </div>
            </div>
          ))}
          {filteredGastos.length === 0 && (
            <div className="py-20 text-center bg-white rounded-3xl border-2 border-dashed border-gray-100">
               <Receipt size={48} className="text-gray-100 mx-auto mb-4" />
               <p className="text-gray-400 font-medium">No hay gastos registrados</p>
            </div>
          )}
        </div>
      </main>

      <Drawer 
        isOpen={mostrarForm} 
        onClose={() => setMostrarForm(false)} 
        title="Registrar Egreso"
      >
        <div className="p-1 space-y-6">
          <div className="space-y-2">
             <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Tipo de Egreso</label>
             <div className="grid grid-cols-2 gap-3">
                {(["GASTO_VARIOS", "SUELDO"] as const).map((t) => (
                  <button 
                    key={t} 
                    onClick={() => setTipo(t)}
                    className={`py-3 rounded-xl text-xs font-bold transition-all border ${tipo === t ? "border-red-600 bg-red-600 text-white shadow-lg shadow-red-600/20" : "border-gray-200 bg-gray-50 text-gray-400 hover:bg-gray-100"}`}>
                    {t === "SUELDO" ? "Sueldo / Personal" : "Gastos Varios"}
                  </button>
                ))}
            </div>
          </div>

          <div className="space-y-6">
            {tipo === "GASTO_VARIOS" ? (
              <>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Proveedor (Opcional)</label>
                  <select value={proveedorId} onChange={(e) => setProveedorId(e.target.value)}
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-bold outline-none uppercase appearance-none cursor-pointer">
                    <option value="">SIN PROVEEDOR ASOCIADO</option>
                    {proveedores.map((p) => <option key={p.id} value={p.id}>{p.nombre.toUpperCase()}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Descripción *</label>
                  <textarea value={descripcion} onChange={(e) => setDescripcion(e.target.value)}
                    placeholder="Detalle el motivo del gasto..."
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-medium outline-none min-h-[80px] resize-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">N° Comprobante (Opcional)</label>
                  <input type="text" value={comprobante} onChange={(e) => setComprobante(e.target.value)}
                    placeholder="Factura, Recibo, etc..."
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-medium outline-none uppercase" />
                </div>
              </>
            ) : (
              <>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Operario / Beneficiario *</label>
                  <input type="text" value={empleado} onChange={(e) => setEmpleado(e.target.value)}
                    placeholder="Nombre completo..."
                    className="w-full px-4 py-3 bg-gray-50 border border-gray-200 focus:border-red-600 rounded-xl text-sm font-medium outline-none uppercase" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Desde</label>
                    <input type="date" value={desde} onChange={(e) => setDesde(e.target.value)}
                      className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Hasta</label>
                    <input type="date" value={hasta} onChange={(e) => setHasta(e.target.value)}
                      className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none" />
                  </div>
                </div>
              </>
            )}

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Método Pago</label>
                <select value={formaPago} onChange={(e) => setFormaPago(e.target.value)}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold outline-none appearance-none cursor-pointer">
                  {FORMAS_PAGO.map((f) => <option key={f} value={f}>{f}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-red-600 uppercase tracking-wider ml-1">Caja Salida *</label>
                <select value={cajaId} onChange={(e) => setCajaId(e.target.value)}
                  className="w-full px-4 py-3 bg-gray-900 text-red-500 border border-transparent rounded-xl text-sm font-bold outline-none appearance-none cursor-pointer">
                  {cajas.map((c) => <option key={c.id} value={c.id}>{c.nombre.toUpperCase()}</option>)}
                </select>
              </div>
            </div>

            <div className="p-6 bg-gray-950 rounded-2xl border-b-4 border-red-600 space-y-2">
              <label className="text-xs font-bold uppercase tracking-wider text-red-600 text-center block">Importe a Pagar *</label>
              <div className="relative">
                <span className="absolute left-0 top-1/2 -translate-y-1/2 text-xl font-bold text-gray-700">$</span>
                <input type="number" min="0" step="0.01" value={importe} onChange={(e) => setImporte(e.target.value)}
                  placeholder="0.00"
                  className="w-full bg-transparent text-white text-3xl font-bold outline-none text-center tabular-nums" />
              </div>
            </div>
          </div>

          <div className="pt-6">
            <button
              onClick={guardar}
              disabled={guardando || !importe || !cajaId}
              className="w-full bg-red-600 text-white py-4 rounded-xl text-sm font-bold hover:bg-red-700 disabled:opacity-50 transition-all shadow-lg shadow-red-600/20 active:scale-[0.98]"
            >
              {guardando ? "Procesando..." : "Confirmar Egreso"}
            </button>
          </div>
        </div>
      </Drawer>

      <ConfirmDialog
        isOpen={!!confirmDelete}
        title="Anular Gasto"
        message="¿Estás seguro de eliminar este registro? Esta acción impactará en el balance de la caja seleccionada."
        confirmLabel={eliminando ? "Eliminando..." : "Sí, eliminar"}
        onCancel={() => setConfirmDelete(null)}
        onConfirm={() => confirmDelete && eliminarGasto(confirmDelete)}
      />
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter, useParams } from "next/navigation";
import { useEffect, useState } from "react";
import Link from "next/link";
import { formatEstado, estadoColors, TODOS_ESTADOS, FLUJO_ESTADOS } from "@/lib/estados";
import { Wrench, Phone, FileText, Send, AlertTriangle, ArrowLeft, Printer, User, Calendar, Briefcase, ChevronRight, CheckCircle2 } from "lucide-react";

export default function OrdenDetallePage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const params = useParams();
  const id = params.id as string;

  const [orden, setOrden] = useState<any | null>(null);
  const [loading, setLoading] = useState(true);
  const [actualizando, setActualizando] = useState(false);

  // Tabs
  const [activeTab, setActiveTab] = useState<"falla" | "revision" | "notas">("falla");
  const [revisionTexto, setRevisionTexto] = useState("");

  // Notas
  const [nuevaNota, setNuevaNota] = useState("");
  const [esSeguimiento, setEsSeguimiento] = useState(false);

  const [mostrarTodosEstados, setMostrarTodosEstados] = useState(false);

  useEffect(() => {
    if (status === "unauthenticated") router.push("/login");
  }, [status, router]);

  const cargarOT = () => {
    fetch(`/api/ordenes/${id}`)
      .then((r) => r.json())
      .then((data) => {
        setOrden(data);
        setRevisionTexto(data.revisionTecnica || "");
        setLoading(false);
      })
      .catch(() => setLoading(false));
  };

  useEffect(() => {
    if (id) cargarOT();
  }, [id]);

  const cambiarEstado = async (nuevoEstado: string) => {
    if (!orden) return;

    // Validación de negocio
    if (nuevoEstado === "PARA_PRESUPUESTAR" && !orden.revisionTecnica?.trim() && !mostrarTodosEstados) {
      alert("No se puede pasar a presupuestar sin una Revisión Técnica guardada por el técnico.");
      setActiveTab("revision");
      return;
    }

    setActualizando(true);
    await fetch(`/api/ordenes/${id}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ estado: nuevoEstado }),
    });
    cargarOT();
    setActualizando(false);
    setMostrarTodosEstados(false);
  };

  const guardarRevision = async () => {
    setActualizando(true);
    await fetch(`/api/ordenes/${id}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ revisionTecnica: revisionTexto }),
    });
    cargarOT();
    setActualizando(false);
    alert("Revisión técnica guardada exitosamente.");
  };

  const enviarNota = async () => {
    if (!nuevaNota.trim()) return;
    setActualizando(true);
    await fetch(`/api/ordenes/${id}/notas`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ texto: nuevaNota, esSeguimiento }),
    });
    setNuevaNota("");
    setEsSeguimiento(false);
    cargarOT();
    setActualizando(false);
  };

  if (status === "loading" || loading) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center font-black uppercase tracking-[0.3em] text-gray-400 animate-pulse">
        Sincronizando Detalles de OT...
      </div>
    );
  }

  if (!orden || orden.error) return <div className="p-10 text-center text-red-600 font-black uppercase tracking-widest bg-gray-50 min-h-screen flex items-center justify-center">REGISTRO DE ORDEN NO IDENTIFICADO</div>;

  const siguientesEstados = FLUJO_ESTADOS[orden.estado] || [];
  const equipoStr = [orden.maquina?.nombre, orden.marca?.nombre, orden.modelo?.nombre].filter(Boolean).join(" - ");

  const totalPresupuestado = orden.presupuestos?.reduce((sum: number, p: any) => {
    const pTotal = p.items?.reduce((s: number, i: any) => s + i.total, 0) || p.total || 0;
    return sum + pTotal;
  }, 0) || 0;

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col font-sans animate-in fade-in duration-500">

      {/* Header Industrial */}
      <header className="bg-white border-b border-gray-300 sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 lg:px-10 h-24 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <Link href="/ordenes" className="p-3 text-gray-400 hover:text-red-600 hover:bg-gray-100 rounded-xl transition-all border border-transparent hover:border-gray-200">
              <ArrowLeft size={24} />
            </Link>
            <div>
              <div className="flex items-center gap-3 text-gray-400 mb-1 lg:mb-0">
                <span className="text-xs font-black uppercase tracking-[0.3em] opacity-70">Operaciones</span>
                <span className="w-1.5 h-1.5 rounded-full bg-red-600 animate-pulse" />
                <span className="text-[10px] font-bold text-red-600 uppercase tracking-widest">EXPEDIENTE TÉCNICO</span>
              </div>
              <div className="flex items-center gap-4">
                 <h1 className="text-3xl lg:text-4xl font-black text-gray-900 tracking-tighter italic uppercase">OT #{orden.numero}</h1>
                 <span className={`px-4 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest border-2 shadow-sm ${estadoColors[orden.estado] || "bg-white border-gray-200 text-gray-500"}`}>
                   {formatEstado(orden.estado)}
                 </span>
              </div>
            </div>
          </div>
          <div className="hidden lg:flex items-center gap-6 pr-4">
             {totalPresupuestado > 0 && (
               <div className="text-right border-r border-gray-200 pr-6 mr-6">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">TOTAL COTIZADO</p>
                  <p className="text-2xl font-black text-emerald-600 italic tracking-tighter">${totalPresupuestado.toLocaleString('es-AR')}</p>
               </div>
             )}
             <button onClick={() => window.print()} className="bg-gray-900 text-white px-8 py-4 rounded-xl text-sm font-black hover:bg-black transition-all shadow-xl shadow-gray-900/20 uppercase tracking-widest flex items-center gap-3">
               <Printer size={20} /> COMPROBANTE
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto px-6 lg:px-10 py-10 w-full grid grid-cols-1 lg:grid-cols-12 gap-10">

        {/* PANEL DE TRANSICION DE ESTADO */}
        <section className="lg:col-span-12">
           <div className="bg-white rounded-3xl p-6 border-2 border-gray-100 shadow-sm flex flex-col md:flex-row items-center gap-6">
              <div className="flex items-center gap-3 text-gray-400">
                 <ChevronRight size={24} className="text-red-600" />
                 <span className="text-xs font-black uppercase tracking-widest">SIGUIENTE ETAPA OPERATIVA:</span>
              </div>
              <div className="flex flex-wrap gap-4 flex-1">
                {siguientesEstados.length > 0 ? (
                    siguientesEstados.map((est: string) => (
                      <button 
                        key={est} 
                        onClick={() => cambiarEstado(est)} 
                        disabled={actualizando} 
                        className={`px-8 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.1em] border-2 transition-all hover:scale-[1.02] active:scale-[0.98] shadow-sm disabled:opacity-50 ${estadoColors[est] || "border-gray-200 bg-gray-50 text-gray-500"}`}>
                        PASAR A {formatEstado(est)}
                      </button>
                    ))
                ) : <span className="text-gray-400 font-black italic text-sm uppercase tracking-widest">FLUJO DE TRABAJO FINALIZADO</span>}
              </div>
              <div className="border-t md:border-t-0 md:border-l border-gray-100 px-6 pt-4 md:pt-0">
                <button onClick={() => setMostrarTodosEstados(!mostrarTodosEstados)} className="text-[10px] text-gray-400 hover:text-red-600 font-black uppercase tracking-widest transition-colors">
                  {mostrarTodosEstados ? "[OCULTAR INTERVENCIÓN MANUAL]" : "[FORZAR TRANSICIÓN MANUAL]"}
                </button>
              </div>
           </div>

           {mostrarTodosEstados && (
             <div className="flex flex-wrap gap-3 mt-6 p-6 bg-gray-900 rounded-3xl border-2 border-gray-800 animate-in slide-in-from-top duration-500">
               {TODOS_ESTADOS.filter((e: string) => e !== orden.estado).map((est: string) => (
                 <button key={est} onClick={() => cambiarEstado(est)} disabled={actualizando} className="px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border-2 border-gray-700 text-gray-400 hover:text-white hover:border-red-600 transition-all">
                   {formatEstado(est)}
                 </button>
               ))}
             </div>
           )}
        </section>

        {/* COLUMNA IZQ: RESUMEN TECNICO-COMERCIAL */}
        <aside className="lg:col-span-4 space-y-10">

            {/* CARD CLIENTE */}
            <div className="bg-white rounded-3xl shadow-2xl border-2 border-gray-100 overflow-hidden">
               <div className="bg-gray-50 px-8 py-5 border-b-2 border-gray-100 flex items-center justify-between">
                 <div className="flex items-center gap-3">
                    <User size={18} className="text-red-600" />
                    <h2 className="font-black text-gray-900 text-xs uppercase tracking-widest">Información Titular</h2>
                 </div>
                 {orden.cliente.id && <Link href={`/clientes/${orden.cliente.id}`} className="text-[10px] font-black text-red-600 hover:underline uppercase">Ver Ficha</Link>}
               </div>
               <div className="p-8 space-y-6">
                 <div>
                    <span className="block text-[10px] uppercase font-black tracking-widest text-gray-400 mb-2">TITULAR / EMPRESA</span>
                    <strong className="text-xl font-black text-gray-900 italic uppercase tracking-tighter block">{orden.cliente.empresa ? `${orden.cliente.empresa.nombre} (${orden.cliente.nombre})` : orden.cliente.nombre}</strong>
                 </div>
                 {orden.cliente.telefono && (
                   <a href={`https://wa.me/${orden.cliente.telefono.replace(/\D/g,'')}`} className="flex items-center gap-4 p-4 bg-emerald-50 rounded-2xl border-2 border-emerald-100 text-emerald-700 hover:bg-emerald-100 transition-all">
                      <Phone size={20} />
                      <div className="flex flex-col">
                         <span className="text-[10px] font-black uppercase tracking-widest opacity-70">COMUNICACIÓN DIRECTA</span>
                         <span className="text-base font-black italic tracking-tight">{orden.cliente.telefono}</span>
                      </div>
                   </a>
                 )}
               </div>
            </div>

            {/* CARD EQUIPO */}
            <div className="bg-white rounded-3xl shadow-2xl border-2 border-gray-100 overflow-hidden">
               <div className="bg-gray-900 px-8 py-5 flex items-center gap-3">
                  <Wrench size={18} className="text-red-600" />
                  <h2 className="font-black text-white text-xs uppercase tracking-widest">Configuración Unidad</h2>
               </div>
               <div className="p-8 space-y-6">
                 <div>
                    <span className="block text-[10px] uppercase font-black tracking-widest text-gray-400 mb-2">MAQUINARIA — MARCA — MODELO</span>
                    <p className="font-black text-gray-900 text-lg italic uppercase tracking-tighter">{equipoStr}</p>
                 </div>
                 {orden.nroSerie && (
                   <div className="bg-gray-50 border-2 border-dashed border-gray-200 p-4 rounded-2xl flex items-center justify-between">
                      <span className="text-[10px] font-black text-gray-400 uppercase">Número de Serie</span>
                      <span className="text-sm font-black text-red-600 font-mono italic tracking-widest">{orden.nroSerie}</span>
                   </div>
                 )}
                 <div>
                    <span className="block text-[10px] uppercase font-black tracking-widest text-gray-400 mb-2">INVENTARIO (RECEPCIÓN)</span>
                    <p className="text-sm font-bold text-gray-600 bg-gray-50 p-4 rounded-xl border border-gray-100 italic">{orden.accesorios || "SIN DETALLE"}</p>
                 </div>
                 <div className="grid grid-cols-2 gap-4 pt-4 border-t border-gray-100">
                    <div>
                       <span className="block text-[9px] font-black text-gray-400 uppercase mb-1">ALTA SISTEMA</span>
                       <div className="flex items-center gap-2 font-black text-gray-900 text-sm italic"><Calendar size={14} className="text-red-600"/>{new Date(orden.fechaRecepcion).toLocaleDateString("es-AR")}</div>
                    </div>
                    <div>
                       <span className="block text-[9px] font-black text-gray-400 uppercase mb-1">PROMESA ENTREGA</span>
                       <div className={`flex items-center gap-2 font-black text-sm italic ${orden.fechaEstimadaEntrega && new Date(orden.fechaEstimadaEntrega) < new Date() ? 'text-red-600 animate-pulse' : 'text-gray-900'}`}>
                          <Calendar size={14} className="opacity-40"/>{orden.fechaEstimadaEntrega ? new Date(orden.fechaEstimadaEntrega).toLocaleDateString("es-AR") : "PND"}
                       </div>
                    </div>
                 </div>
               </div>
            </div>

            {/* CARD PRESUPUESTOS */}
            <div className="bg-white rounded-3xl shadow-2xl border-2 border-gray-100 overflow-hidden">
               <div className="bg-gray-50 px-8 py-5 border-b-2 border-gray-100 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                     <FileText size={18} className="text-red-600" />
                     <h2 className="font-black text-gray-900 text-xs uppercase tracking-widest">Historial de Costos</h2>
                  </div>
               </div>
               <div className="p-6 space-y-4">
                 {orden.presupuestos.length === 0 ? (
                    <div className="text-center py-8 opacity-30 flex flex-col items-center gap-3">
                       <FileText size={32} />
                       <p className="text-[10px] font-black uppercase tracking-widest">Sin cotizaciones activas</p>
                    </div>
                 ) : 
                   orden.presupuestos.map((p: any) => (
                     <div key={p.id} onClick={() => router.push(`/presupuestos/${p.id}`)} className="p-5 border-2 border-gray-100 rounded-2xl cursor-pointer hover:border-red-600 transition-all bg-white group shadow-sm active:scale-[0.98]">
                        <div className="flex justify-between items-center mb-3">
                          <span className="font-black text-gray-900 text-sm italic tracking-tighter uppercase group-hover:text-red-600 transition-colors">Cotización #{p.numero}</span>
                          <span className={`text-[9px] font-black px-2 py-0.5 rounded border ${p.estado === 'APROBADO' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : p.estado === 'RECHAZADO' ? 'bg-red-50 text-red-700 border-red-100' : 'bg-gray-50 text-gray-500 border-gray-200'}`}>{p.estado}</span>
                        </div>
                        <div className="text-2xl font-black text-red-600 italic tracking-tighter">${p.total?.toLocaleString('es-AR')}</div>
                     </div>
                   ))
                 }
                 {(orden.estado === "PARA_PRESUPUESTAR" || orden.estado === "REVISADO") && (
                   <button onClick={() => router.push(`/presupuestos/nuevo?otId=${orden.id}`)} className="w-full mt-2 bg-red-600 text-white rounded-2xl py-5 text-xs font-black hover:bg-red-700 shadow-xl shadow-red-600/20 uppercase tracking-widest transition-all">+ GENERAR COTIZACIÓN</button>
                 )}
               </div>
            </div>
        </aside>

        {/* COLUMNA DERECHA: FLUJO DINAMICO (TABS) */}
        <div className="lg:col-span-8 space-y-10">
           <div className="bg-white rounded-3xl shadow-2xl border-2 border-gray-100 overflow-hidden h-full flex flex-col">

               {/* Nav Industrial V3 */}
               <div className="flex border-b-2 border-gray-100 bg-gray-50/50 overflow-x-auto">
                 <button onClick={() => setActiveTab('falla')} className={`px-10 py-6 text-xs font-black uppercase tracking-widest transition-all relative ${activeTab === 'falla' ? 'text-red-600 bg-white' : 'text-gray-400 hover:text-gray-900 border-transparent'}`}>
                    REPORTE FALLA
                    {activeTab === 'falla' && <span className="absolute bottom-0 left-0 w-full h-1 bg-red-600" />}
                 </button>
                 <button onClick={() => setActiveTab('revision')} className={`px-10 py-6 text-xs font-black uppercase tracking-widest transition-all relative flex items-center gap-3 ${activeTab === 'revision' ? 'text-red-600 bg-white' : 'text-gray-400 hover:text-gray-900 border-transparent'}`}>
                    REVISIÓN TÉCNICA
                    {!orden.revisionTecnica && <span className="w-2.5 h-2.5 rounded-full bg-red-600 animate-pulse"></span>}
                    {activeTab === 'revision' && <span className="absolute bottom-0 left-0 w-full h-1 bg-red-600" />}
                 </button>
                 <button onClick={() => setActiveTab('notas')} className={`px-10 py-6 text-xs font-black uppercase tracking-widest transition-all relative flex items-center gap-3 ${activeTab === 'notas' ? 'text-red-600 bg-white' : 'text-gray-400 hover:text-gray-900 border-transparent'}`}>
                    BITÁCORA INTERNA
                    <span className="bg-gray-200 text-gray-500 text-[9px] px-2 py-0.5 rounded-full font-black">{orden.notas?.length || 0}</span>
                    {activeTab === 'notas' && <span className="absolute bottom-0 left-0 w-full h-1 bg-red-600" />}
                 </button>
               </div>

               {/* Tab Content Industrial */}
               <div className="p-10 flex-1">
                  {activeTab === 'falla' && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-left duration-500">
                      <div>
                         <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 pl-1">DESCRIPCIÓN OPERATIVA DEL CLIENTE</h3>
                         <div className="bg-gray-50 p-8 rounded-3xl border-2 border-gray-100 text-lg font-bold text-gray-800 italic uppercase tracking-tight whitespace-pre-wrap shadow-inner leading-relaxed">
                            {orden.falla || "REGISTRO DE FALLA NO ESPECIFICADO EN RECEPCIÓN."}
                         </div>
                      </div>
                      {orden.observaciones && (
                        <div className="bg-red-50 p-8 rounded-3xl border-2 border-red-100 text-sm text-red-900 uppercase italic font-black shadow-sm leading-relaxed">
                           <span className="text-red-600 text-[10px] font-black mb-2 block tracking-widest">NOTA DE ADMINISTRACIÓN:</span>
                           {orden.observaciones}
                        </div>
                      )}
                    </div>
                  )}

                  {activeTab === 'revision' && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right duration-500 h-full flex flex-col">
                      <div className="flex items-center justify-between mb-2">
                         <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest pl-1">DIAGNÓSTICO TÉCNICO AVANZADO {orden.tecnico?.nombre ? `[ RESPONSABLE: ${orden.tecnico.nombre.toUpperCase()} ]` : ''}</h3>
                         <CheckCircle2 className={`${orden.revisionTecnica ? "text-emerald-500" : "text-gray-200"}`} />
                      </div>
                      <textarea 
                         value={revisionTexto} onChange={e => setRevisionTexto(e.target.value)}
                         className="w-full flex-1 min-h-[300px] p-8 bg-gray-50 border-2 border-gray-100 rounded-3xl outline-none focus:border-red-600 focus:bg-white text-lg font-bold italic tracking-tight placeholder:italic transition-all shadow-inner leading-relaxed"
                         placeholder="Detallar diagnóstico técnico, repuestos necesarios y observaciones para validación comercial..."
                      />
                      <div className="flex justify-end pt-4">
                         <button onClick={guardarRevision} disabled={actualizando} className="bg-gray-900 text-white px-10 py-5 rounded-2xl text-xs font-black hover:bg-black disabled:opacity-50 transition-all uppercase tracking-widest shadow-xl shadow-gray-900/20 active:scale-95">SALVAR EXPEDIENTE TÉCNICO</button>
                      </div>
                    </div>
                  )}

                  {activeTab === 'notas' && (
                    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
                       {/* Editor de Notas */}
                       <div className="bg-gray-50 border-2 border-gray-100 p-8 rounded-3xl space-y-6 shadow-sm">
                          <textarea value={nuevaNota} onChange={e => setNuevaNota(e.target.value)} className="w-full p-6 bg-white border-2 border-gray-100 rounded-2xl text-base font-bold italic outline-none focus:border-red-600 shadow-sm transition-all" rows={3} placeholder="REGISTRAR NUEVO EVENTO O ALERTA..." />
                          <div className="flex flex-col sm:flex-row items-center justify-between gap-6">
                             <label className="flex items-center gap-4 text-xs text-red-600 cursor-pointer font-black p-4 bg-red-50 rounded-2xl border-2 border-red-100 hover:bg-red-100 transition-all active:scale-95">
                                <input type="checkbox" checked={esSeguimiento} onChange={e => setEsSeguimiento(e.target.checked)} className="w-6 h-6 text-red-600 border-2 border-red-600 rounded focus:ring-red-600" />
                                <AlertTriangle size={20}/> ACTIVAR ALERTA EN DASHBOARD
                             </label>
                             <button onClick={enviarNota} disabled={actualizando} className="w-full sm:w-auto bg-red-600 text-white px-8 py-5 rounded-2xl text-xs font-black flex items-center justify-center gap-3 hover:bg-red-700 shadow-xl shadow-red-600/20 uppercase tracking-widest transition-all active:scale-95 font-sans"><Send size={18}/> PUBLICAR NOTA</button>
                          </div>
                       </div>

                       {/* Timeline de Notas */}
                       <div className="space-y-6 max-h-[500px] overflow-y-auto pr-4 custom-scrollbar">
                         {orden.notas?.map((nota: any) => (
                           <div key={nota.id} className={`p-8 rounded-3xl border-2 transition-all hover:border-red-600 group relative ${nota.esSeguimiento ? 'bg-red-50 border-red-200' : 'bg-white border-gray-100 shadow-sm'}`}>
                             {nota.esSeguimiento && <AlertTriangle size={24} className="absolute -top-3 -right-3 text-red-600 bg-white rounded-full p-1 border-2 border-red-600 shadow-lg" />}
                             <div className="flex justify-between items-start mb-4 text-[10px] font-black uppercase tracking-widest">
                               <div className="flex items-center gap-2">
                                  <User size={12} className="text-gray-400"/>
                                  <span className="text-gray-900 italic">{nota.usuario?.nombre || 'SISTEMA'}</span>
                               </div>
                               <span className="text-gray-400 tabular-nums">{new Date(nota.fecha).toLocaleString('es-AR')}</span>
                             </div>
                             <p className={`text-base font-bold italic tracking-tight leading-relaxed ${nota.esSeguimiento ? 'text-red-900' : 'text-gray-700'}`}>{nota.texto}</p>
                           </div>
                         ))}
                         {(!orden.notas || orden.notas.length === 0) && (
                            <div className="text-center py-20 opacity-20 flex flex-col items-center gap-4">
                               <Briefcase size={64} />
                               <p className="text-[10px] font-black uppercase tracking-[0.3em]">Sin registro de actividad</p>
                            </div>
                         )}
                       </div>
                    </div>
                  )}
               </div>

           </div>
        </div>
      </main>
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState, useRef } from "react";
import Link from "next/link";
import { ArrowLeft, Plus, Save, Wrench, User, Calendar, Briefcase, AlertTriangle, CheckSquare, Search } from "lucide-react";

interface Item { id: string; nombre: string; }
interface Cliente extends Item { empresa?: { nombre: string } | null; telefono?: string; }

function ComboBox({ label, value, onChange, opciones, placeholder, rows }: any) {
  const [abierto, setAbierto] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  const filtradas = opciones.filter((o: string) => o.toLowerCase().includes(value.toLowerCase()) && o !== value);

  useEffect(() => {
    const handler = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) setAbierto(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  return (
    <div ref={ref} className="relative">
      <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-3 pl-1">{label}</label>
      {rows && rows > 1 ? (
        <textarea
          value={value} onChange={(e) => { onChange(e.target.value); setAbierto(true); }} onFocus={() => setAbierto(true)}
          rows={rows} className="w-full px-6 py-5 bg-gray-50 border-2 border-gray-100 rounded-2xl text-base font-bold outline-none focus:border-red-600 transition-all uppercase italic tracking-tight placeholder:opacity-30" placeholder={placeholder}
        />
      ) : (
        <input
          type="text" value={value} onChange={(e) => { onChange(e.target.value); setAbierto(true); }} onFocus={() => setAbierto(true)}
          className="w-full px-6 py-5 bg-gray-50 border-2 border-gray-100 rounded-2xl text-base font-bold outline-none focus:border-red-600 transition-all uppercase italic tracking-tight placeholder:opacity-30" placeholder={placeholder}
        />
      )}
      {abierto && filtradas.length > 0 && (
        <div className="absolute z-20 w-full mt-2 bg-white border-2 border-gray-100 rounded-2xl shadow-2xl max-h-60 overflow-y-auto overflow-hidden">
          {filtradas.map((o: string, i: number) => (
            <button key={i} onClick={() => { onChange(o); setAbierto(false); }} className="w-full text-left px-6 py-4 text-sm font-black uppercase tracking-widest hover:bg-gray-50 border-b border-gray-100 last:border-0 transition-colors">
              {o}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

