                <div className="bg-gray-50 px-8 py-5 border-b-2 border-gray-100 flex items-center justify-between group cursor-pointer" onClick={() => router.push(`/ordenes/${ppto.orden!.id}`)}>
                    <div className="flex items-center gap-3">
