import { NextAuthOptions } from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";
import { prisma } from "./prisma";
import bcrypt from "bcryptjs";

export const authOptions: NextAuthOptions = {
  providers: [
    CredentialsProvider({
      name: "Credentials",
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        if (!credentials?.email || !credentials?.password) return null;

        const user = await prisma.usuario.findUnique({
          where: { email: credentials.email },
        });

        if (!user || !user.activo) return null;

        const isValid = await bcrypt.compare(credentials.password, user.password);
        if (!isValid) return null;

        return {
          id: user.id,
          name: user.nombre,
          email: user.email,
          role: user.rol,
        };
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user }) {
      if (user) {
        token.role = (user as any).role;
        token.id = user.id;
      }
      return token;
    },
    async session({ session, token }) {
      if (session.user) {
        (session.user as any).role = token.role;
        (session.user as any).id = token.id;
      }
      return session;
    },
  },
  pages: {
    signIn: "/login",
  },
  session: {
    strategy: "jwt",
  },
  secret: process.env.NEXTAUTH_SECRET,
};

/**
 * Roles disponibles en el sistema según schema.prisma:
 * ADMIN, TECNICO, CAJA, VENTAS
 */

export const ROLES = {
  ADMIN: "ADMIN",
  TECNICO: "TECNICO",
  CAJA: "CAJA",
  VENTAS: "VENTAS",
} as const;

type Role = keyof typeof ROLES;

export const permissions = {
  /**
   * Solo el ADMIN tiene control total.
   */
  isAdmin(role?: string | null): boolean {
    return role === ROLES.ADMIN;
  },

  /**
   * Para cobrar o ver finanzas fuertes, se requiere ADMIN o CAJA.
   */
  canManageFinances(role?: string | null): boolean {
    return role === ROLES.ADMIN || role === ROLES.CAJA;
  },

  /**
   * Técnicos pueden editar OTs y sus estados de diagnóstico.
   * Admin y Ventas también. Caja generalmente no edita reparaciones.
   */
  canEditOT(role?: string | null): boolean {
    return role === ROLES.ADMIN || role === ROLES.TECNICO || role === ROLES.VENTAS;
  },

  /**
   * Borrar registros (Hard Delete) solo permitido a ADMIN.
   */
  canDelete(role?: string | null): boolean {
    return role === ROLES.ADMIN;
  }
};

import { prisma } from "@/lib/prisma";

export const cajaService = {
  /**
   * Obtiene todas las cajas con sus saldos actuales.
   * El saldo se calcula como SUM(ingresos) - SUM(egresos) en base a la fecha de filtro.
   */
  async getSaldosCajas(hastaFecha?: Date) {
    const cajas = await prisma.caja.findMany();

    const saldos = await Promise.all(cajas.map(async (caja) => {
      const movimientos = await prisma.movimientoCaja.aggregate({
        where: {
          cajaId: caja.id,
          ...(hastaFecha ? { fecha: { lte: hastaFecha } } : {})
        },
        _sum: {
          ingreso: true,
          egreso: true,
        }
      });

      const ingreso = movimientos._sum.ingreso || 0;
      const egreso = movimientos._sum.egreso || 0;

      return {
        ...caja,
        saldo: ingreso - egreso,
        ingresosTotales: ingreso,
        egresosTotales: egreso,
      };
    }));

    return saldos;
  },

  /**
   * Obtiene el historial de movimientos de una caja específica.
   */
  async getMovimientos(cajaId: string, limit: number = 50) {
    return await prisma.movimientoCaja.findMany({
      where: { cajaId },
      orderBy: { fecha: 'desc' },
      take: limit,
      include: {
        caja: true,
      }
    });
  },

  /**
   * Obtiene los cheques próximos a vencer o vencidos en la Caja de Cheques.
   * Supone que existe una consulta a la tabla Cheque y asocia a clientes.
   */
  async getChequesEstado() {
    const hoy = new Date();
    // Aproximadamente 7 días hacia adelante
    const proximaSemana = new Date(hoy.getTime() + 7 * 24 * 60 * 60 * 1000);

    const cheques = await prisma.cheque.findMany({
      where: {
        estado: 'EN_CARTERA', // Solo cheques que tenemos físicamente
      },
      include: { cliente: true },
      orderBy: { fechaCobro: 'asc' }
    });

    return cheques.map((cheque: any) => {
      if (!cheque.fechaCobro) return { ...cheque, status: 'UNKNOWN', diasDif: 0 };

      const dif = cheque.fechaCobro.getTime() - hoy.getTime();
      const diasDif = Math.ceil(dif / (1000 * 3600 * 24));

      let status = 'OK';
      if (diasDif < 0) status = 'VENCIDO';
      else if (diasDif <= 7) status = 'PROXIMO';

      return { ...cheque, status, diasDif };
    });
  }
};

import { prisma } from "@/lib/prisma";
import { cuentaCorrienteService } from "./cuentaCorrienteService";
import { presupuestoService } from "./presupuestoService";

export const cobranzaService = {
  /**
   * Registra una nueva cobranza y afecta la Caja y la Cuenta Corriente simultáneamente.
   * Valida saldos para no cobrar de más si está vinculado a un Presupuesto.
   */
  async registrarCobranza(data: any) {
    return await prisma.$transaction(async (tx: any) => {
      // 1. Validar que no se cobre más que el saldo si es un cobro a Presupuesto
      if (data.presupuestoId) {
        const saldoPendiente = await presupuestoService.calcularSaldoPresupuesto(data.presupuestoId);
        if (data.importe > saldoPendiente) {
          throw new Error(`El importe (${data.importe}) supera el saldo pendiente del presupuesto (${saldoPendiente})`);
        }
      }

      // 2. Crear cobranza
      const cobranza = await tx.cobranza.create({
        data: {
          tipo: data.tipo || 'PRESUPUESTO',
          importe: data.importe,
          formaPago: data.formaPago || 'Efectivo',
          descripcion: data.descripcion,
          clienteId: data.clienteId,
          presupuestoId: data.presupuestoId,
          cajaId: data.cajaId,
          usuarioId: data.usuarioId,
          chequeId: data.chequeId,
        },
      });

      // 3. Impactar Cuenta Corriente del Cliente (Como HABER, resta deuda)
      if (data.clienteId) {
        await cuentaCorrienteService.registrarMovimiento(tx, {
          clienteId: data.clienteId,
          tipo: 'HABER',
          origen: 'COBRANZA',
          monto: data.importe,
          cobranzaId: cobranza.id,
        });
      }

      // 4. Impactar Caja General (Ingreso)
      await tx.movimientoCaja.create({
        data: {
          fecha: new Date(),
          descripcion: `Cobranza #${cobranza.id.slice(-5)} - ${data.descripcion || ''}`,
          ingreso: data.importe,
          egreso: 0,
          formaPago: data.formaPago,
          cajaId: data.cajaId,
          cobranzaId: cobranza.id,
        }
      });

      // 5. Actualizar estado de cobro en el Presupuesto, si aplica
      if (data.presupuestoId) {
        const saldoPendiente = await presupuestoService.calcularSaldoPresupuesto(data.presupuestoId);
        // Descontamos este importe manualmente porque calcularSaldoPresupuesto usa la DB sin la tx en curso
        const nuevoSaldo = saldoPendiente - data.importe; 

        let nuevoEstadoCobro = "PARCIAL";
        if (nuevoSaldo <= 0) {
          nuevoEstadoCobro = "COBRADO";
        }

        await tx.presupuesto.update({
          where: { id: data.presupuestoId },
          data: { estadoCobro: nuevoEstadoCobro as any }
        });
      }

      return cobranza;
    });
  }
};

import { prisma } from "@/lib/prisma";
import { TipoMovimientoCuenta, OrigenMovimientoCuenta } from "@prisma/client";

export const cuentaCorrienteService = {
  /**
   * Registra un movimiento en la cuenta corriente del cliente.
   * Internamente no hace commit/rollback porque Prisma no tiene un Unit of Work nativo
   * en llamadas separadas a menos que se use \$transaction().
   * Se recomienda llamar a este método dentro de una transacción cuando sea posible.
   */
  async registrarMovimiento(
    tx: any, // Prisma Transaction Client
    data: {
      clienteId: string;
      tipo: TipoMovimientoCuenta;
      origen: OrigenMovimientoCuenta;
      monto: number;
      presupuestoId?: string;
      cobranzaId?: string;
    }
  ) {
    const db = tx || prisma;

    return await db.cuentaCorriente.create({
      data: {
        clienteId: data.clienteId,
        tipo: data.tipo,
        origen: data.origen,
        monto: data.monto,
        presupuestoId: data.presupuestoId,
        cobranzaId: data.cobranzaId,
      },
    });
  },

  /**
   * Consulta el saldo actual de un cliente específico,
   * calculando: SUM(DEBE) - SUM(HABER)
   */
  async getSaldoCliente(clienteId: string): Promise<number> {
    const agrupado = await prisma.cuentaCorriente.groupBy({
      by: ["tipo"],
      where: { clienteId },
      _sum: { monto: true },
    });

    let totalDebe = 0;
    let totalHaber = 0;

    for (const mov of agrupado) {
      if (mov.tipo === "DEBE") totalDebe += mov._sum.monto || 0;
      if (mov.tipo === "HABER") totalHaber += mov._sum.monto || 0;
    }

    return totalDebe - totalHaber;
  },

  /**
   * Obtiene todos los movimientos de cuenta de un cliente, ordenados por fecha descendente.
   */
  async getHistorialMovimientos(clienteId: string) {
    return await prisma.cuentaCorriente.findMany({
      where: { clienteId },
      orderBy: { fecha: "desc" },
      include: {
        presupuesto: { select: { numero: true, items: true } },
        cobranza: { select: { descripcion: true, importe: true } },
      },
    });
  },
};

import { prisma } from "@/lib/prisma";

export const gastoService = {
  /**
   * Registra un nuevo gasto, asegurando que se descuente de la caja seleccionada.
   */
  async registrarGasto(data: any) {
    if (!data.cajaId) {
      throw new Error("La caja es obligatoria para registrar un gasto.");
    }

    return await prisma.$transaction(async (tx: any) => {
      // 1. Crear el Gasto
      const gasto = await tx.gasto.create({
        data: {
          tipo: data.tipo || 'GASTO_VARIOS',
          descripcion: data.descripcion,
          importe: data.importe,
          formaPago: data.formaPago || 'Efectivo',
          comprobante: data.comprobante,
          cajaId: data.cajaId,
          proveedorId: data.proveedorId,
          usuarioId: data.usuarioId,
        }
      });

      // 2. Descontar de la caja
      await tx.movimientoCaja.create({
        data: {
          fecha: new Date(),
          descripcion: `Gasto #${gasto.id.slice(-5)} - ${data.descripcion}`,
          ingreso: 0,
          egreso: data.importe,
          formaPago: data.formaPago,
          cajaId: data.cajaId,
          gastoId: gasto.id,
        }
      });

      return gasto;
    });
  }
};

import { prisma } from "@/lib/prisma";

export const notificacionService = {
  /**
   * Encola un mensaje para ser enviado luego. 
   * @param tipo "WHATSAPP" o "EMAIL"
   * @param destinatario N° de telefono o Email
   * @param payload Objeto libre que luego será parseado
   * @param horasDelay Demora en horas (0 = enviar lo antes posible)
   */
  async encolar(
    tipo: "WHATSAPP" | "EMAIL",
    destinatario: string,
    payload: any,
    horasDelay: number = 0
  ) {
    const procesarDespuesDe = new Date();
    procesarDespuesDe.setHours(procesarDespuesDe.getHours() + horasDelay);

    return await prisma.colaMensajes.create({
      data: {
        tipoNotificacion: tipo,
        destinatario,
        datos: JSON.stringify(payload),
        procesarDespuesDe,
      }
    });
  },

  /**
   * Método que debe ser llamado por un CRON Job (Ej: /api/cron) cada cierta cantidad de minutos.
   */
  async procesarCola() {
    const ahora = new Date();

    // 1. Buscar mensajes pendientes cuyo tiempo de espera ya venció
    const pendientes = await prisma.colaMensajes.findMany({
      where: {
        estado: "PENDIENTE",
        procesarDespuesDe: { lte: ahora }
      },
      take: 20 // Lote para no saturar
    });

    for (const msg of pendientes) {
      try {
        const datos = JSON.parse(msg.datos);

        if (msg.tipoNotificacion === "WHATSAPP") {
          // Acá iría la integración real (Baileys, Meta API, etc.)
          console.log(`[WA_SIMULATOR] Enviando WhatsApp a ${msg.destinatario}:`, datos);
        } else if (msg.tipoNotificacion === "EMAIL") {
          // Acá iría Resend or Nodemailer
          console.log(`[EMAIL_SIMULATOR] Enviando Email a ${msg.destinatario}:`, datos);
        }

        // Marcar como enviado
        await prisma.colaMensajes.update({
          where: { id: msg.id },
          data: { estado: "ENVIADO" }
        });

      } catch (error) {
        console.error(`Error procesando mensaje cola ID ${msg.id}:`, error);
        // Incrementar reintentos
        await prisma.colaMensajes.update({
          where: { id: msg.id },
          data: { 
            estado: msg.reintentos >= 3 ? "ERROR" : "PENDIENTE",
            reintentos: msg.reintentos + 1 
          }
        });
      }
    }

    return pendientes.length;
  }
};

import { prisma } from "@/lib/prisma";
import { cuentaCorrienteService } from "./cuentaCorrienteService";

export const presupuestoService = {
  /**
   * Calcula el total de un presupuesto aplicando IVA si corresponde.
   * items.total = cantidad * precio (siempre sin IVA).
   * El IVA se aplica sobre el subtotal a nivel de presupuesto.
   */
  calcularTotal(items: { total: number }[], incluyeIva: boolean): { subtotal: number; total: number } {
    const subtotal = items.reduce((acc, item) => acc + item.total, 0);
    const total = incluyeIva ? subtotal * 1.21 : subtotal;
    return { subtotal, total };
  },

  /**
   * Calcula el Saldo de un presupuesto específico (Total con IVA - Pagado).
   */
  async calcularSaldoPresupuesto(presupuestoId: string): Promise<number> {
    const presupuesto = await prisma.presupuesto.findUnique({
      where: { id: presupuestoId },
      include: { items: true, cobranzas: true },
    });

    if (!presupuesto) return 0;

    const { total } = this.calcularTotal(presupuesto.items, presupuesto.incluyeIva);
    const pagado = presupuesto.cobranzas.reduce((acc, cobro) => acc + cobro.importe, 0);
    return total - pagado;
  },

  /**
   * Crea un nuevo presupuesto.
   */
  async crearPresupuesto(data: any) {
    return await prisma.$transaction(async (tx: any) => {
      const presupuesto = await tx.presupuesto.create({
        data: {
          clienteId: data.clienteId,
          ordenId: data.ordenId || null,
          usuarioId: data.usuarioId,
          moneda: data.moneda || "ARS",
          formaPago: data.formaPago || "Contado",
          validezDias: data.validezDias || 7,
          incluyeIva: data.incluyeIva ?? false,
          observaciones: data.observaciones || null,
          estado: data.estado || "PRESUPUESTADO",
          estadoCobro: "APROBACION_PENDIENTE",
          items: {
            create: data.items.map((item: any) => ({
              cantidad: item.cantidad,
              descripcion: item.descripcion,
              precio: item.precio,
              total: item.cantidad * item.precio,
            })),
          },
        },
        include: { items: true },
      });

      // Si nace ya como APROBADO, impactar CC
      if (presupuesto.estado === "APROBADO") {
        const { total } = this.calcularTotal(presupuesto.items, presupuesto.incluyeIva);
        await cuentaCorrienteService.registrarMovimiento(tx, {
          clienteId: presupuesto.clienteId,
          tipo: "DEBE",
          origen: "PRESUPUESTO",
          monto: total,
          presupuestoId: presupuesto.id,
        });
      }

      return presupuesto;
    });
  },

  /**
   * Aprueba un presupuesto y registra el DEBE en Cuenta Corriente con el total correcto (con IVA si aplica).
   */
  async aprobarPresupuesto(presupuestoId: string) {
    return await prisma.$transaction(async (tx: any) => {
      const presupuesto = await tx.presupuesto.findUnique({
        where: { id: presupuestoId },
        include: { items: true },
      });

      if (!presupuesto || presupuesto.estado === "APROBADO") return null;

      const actualizado = await tx.presupuesto.update({
        where: { id: presupuestoId },
        data: { estado: "APROBADO", estadoCobro: "COBRO_PENDIENTE" },
      });

      // Usar total con IVA aplicado para el asiento contable
      const { total } = this.calcularTotal(presupuesto.items, presupuesto.incluyeIva);

      await cuentaCorrienteService.registrarMovimiento(tx, {
        clienteId: presupuesto.clienteId,
        tipo: "DEBE",
        origen: "PRESUPUESTO",
        monto: total,
        presupuestoId: presupuesto.id,
      });

      return actualizado;
    });
  },

  /**
   * Actualiza los ítems de un presupuesto y, si ya está APROBADO,
   * recalcula y actualiza el asiento DEBE en CuentaCorriente.
   */
  async actualizarItems(presupuestoId: string, items: { cantidad: number; descripcion: string; precio: number }[]) {
    return await prisma.$transaction(async (tx: any) => {
      const presupuesto = await tx.presupuesto.findUnique({
        where: { id: presupuestoId },
        select: { estado: true, clienteId: true, incluyeIva: true },
      });

      if (!presupuesto) throw new Error("Presupuesto no encontrado");

      // Reemplazar todos los items
      await tx.itemPresupuesto.deleteMany({ where: { presupuestoId } });
      await tx.presupuesto.update({
        where: { id: presupuestoId },
        data: {
          items: {
            create: items.map((item) => ({
              cantidad: item.cantidad,
              descripcion: item.descripcion,
              precio: item.precio,
              total: item.cantidad * item.precio,
            })),
          },
        },
      });

      // Si ya estaba aprobado, actualizar el asiento DEBE en CuentaCorriente
      if (presupuesto.estado === "APROBADO") {
        // Borrar asiento anterior de este presupuesto
        await tx.cuentaCorriente.deleteMany({
          where: { presupuestoId, tipo: "DEBE" },
        });

        // Recalcular con los nuevos items
        const subtotal = items.reduce((acc, item) => acc + item.cantidad * item.precio, 0);
        const total = presupuesto.incluyeIva ? subtotal * 1.21 : subtotal;

        await cuentaCorrienteService.registrarMovimiento(tx, {
          clienteId: presupuesto.clienteId,
          tipo: "DEBE",
          origen: "PRESUPUESTO",
          monto: total,
          presupuestoId,
        });
      }

      return { success: true };
    });
  },
};
